window.PAPERS = [{"id":"2506.13131","title":"AlphaEvolve: A coding agent for scientific and algorithmic discovery","authors":["Alexander"],"affiliations":"Google DeepMind","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-06-16","priority":9.45,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper defines the new state-of-the-art for your primary research focus (LLM evolutionary search). It transitions from single-function evolution (FunSearch) to full-codebase evolution via diffs and introduces meta-prompt evolution, directly addressing your goals of 'Evolving the Evolver' and scalability.","relevance":{"methodological":10,"problem":10,"inspirational":10},"brief":"AlphaEvolve extends FunSearch by evolving entire code files (rather than single functions) using a 'search/replace' diff format and Gemini 2.0, achieving SOTA results across matrix multiplication (beating Strassen), 50+ open math problems, and Google's production scheduling. The results are exceptionally strong and verified, including deployed improvements to Google's Borg scheduler (0.7% resource recovery) and TPU circuits. The critical takeaway is the move to **diff-based full-file evolution** and **meta-prompt evolution** (evolving the prompt instructions alongside the code), which allows the system to modify architecture and logic rather than just heuristics. This is a mandatory blueprint for the next iteration of our AlgoEvo and EvoCut projects.","specific_domain":"","methods":["llm_evolutionary_search","evolutionary_algorithm","code_generation","program_synthesis","llm_as_heuristic","llm_as_evaluator","automated_evaluation","map_elites"],"problems":["scientific_discovery","algorithm_discovery","matrix_multiplication","mathematical_discovery","combinatorial_packing","geometric_problems"],"problem_short":"AlphaEvolve","benchmarks":["Tensor decomposition for matrix multiplication (54 sizes ⟨m,n,p⟩)","Autocorrelation inequalities","Uncertainty principles","Erdős’s minimum overlap problem","Kissing number problem (11 dimensions)","Packing problems (hexagons, points, circles)","Heilbronn problem (triangles, convex regions)","Sums and differences of finite sets","Google’s cluster management system (Borg)","Gemini kernel engineering (Pallas kernels for matrix multiplication)","TPU arithmetic circuit design (Verilog)","FlashAttention kernel (XLA-generated IR)"],"baselines":["Strassen (1969)","Fawzi et al. [26] (AlphaTensor)","Hopcroft and Kerr [42]","Smirnov [93, 91, 92]","Kauers and Moosbauer [47, 48]","Laderman [52]","Moosbauer and Poole [72]","Previous SOTA for mathematical problems [17, 70, 104, 33, 39, 107, 31, 29]","Existing production heuristic (Google data centers)","Expert-designed heuristic (Gemini kernel)","Highly optimized Verilog implementation (TPU circuit)","Compiler-generated and highly optimized XLA IR (FlashAttention)"],"vs_baselines":{"Strassen (1969)":"4x4 complex-valued matrices: 48 scalar multiplications (vs 49)","Fawzi et al. [26]":"4x4 matrices: 48 scalar multiplications (vs 47 for field with 2 elements, AlphaEvolve is for any field)","Previous SOTA (mathematics)":"surpassed on ~20% of 50+ problems, matched on ~75%","Erdős’s minimum overlap problem [40]":"0.380924 (vs 0.380927)","Kissing number (11D) [31]":"593 (vs 592)","Packing 11 unit hexagons [29]":"3.931 side length (vs 3.943)","Packing 12 unit hexagons [29]":"3.942 side length (vs 4.0)","Min/Max distance (16 pts, 2D) [29]":"sqrt(12.889266112) (vs sqrt(12.890))","Min/Max distance (14 pts, 3D) [29]":"sqrt(4.165849767) (vs sqrt(4.168))","Heilbronn (triangle, 11 pts) [29]":">=0.0365 area (vs 0.036)","Heilbronn (convex, 13 pts) [29]":">=0.0309 area (vs 0.0306)","Heilbronn (convex, 14 pts) [29]":">=0.0278 area (vs 0.0277)","Packing circles (26, unit square) [29]":">=2.635 sum of radii (vs 2.634)","Packing circles (32, unit square) [29]":">=2.937 sum of radii (vs 2.936)","Packing circles (21, perimeter 4) [29]":">=2.3658 sum of radii (vs 2.364)","Existing production heuristic (Google data centers)":"recovers 0.7% fleet-wide compute resources","Expert-designed heuristic (Gemini kernel)":"23% kernel speedup, 1% reduction in Gemini training time","Highly optimized Verilog (TPU circuit)":"simple code rewrite removing unnecessary bits","XLA-generated IR (FlashAttention)":"kernel sped up by 32%, pre/postprocessing by 15%"},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaTensor","framework_lineage":"alphaevolve","llm_model":"Gemini 2.0 Flash, Gemini 2.0 Pro","code_url":"https://colab.research.google.com/github/google-deepmind/alphaevolve_results/blob/master/mathematical_results.ipynb","new_benchmark":false,"confidence_results":"lo"},{"id":"2601.16175","title":"Learning to Discover at Test Time","authors":["Mert"],"affiliations":"Stanford University, NVIDIA, UC San Diego, Together AI, Astera Institute","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-01-22","priority":8.96,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly challenges and improves upon the AlphaEvolve/ShinkaEvolve paradigms central to our research by demonstrating that test-time weight updates (RL) significantly outperform frozen-model context evolution. It provides a concrete recipe (entropic objective + PUCT) for 'RL-infused evolution' that we list as a primary focus.","relevance":{"methodological":9,"problem":10,"inspirational":10},"brief":"TTT-Discover introduces a method to fine-tune an LLM (gpt-oss-120b) *during* inference on a single test problem using RL, replacing the frozen-model evolutionary search of AlphaEvolve. They employ a novel 'entropic objective' that optimizes for the single best solution (discovery) rather than expected return, combined with PUCT-based state reuse. The results are empirically rigorous, setting new SOTA on Erdős’ problem, GPU kernel optimization, and AtCoder contests, directly beating AlphaEvolve and ShinkaEvolve. The critical takeaway is that for hard discovery tasks, shifting the model's distribution via online updates is superior to context-based search; we should immediately test their entropic objective in our AlgoEvo pipeline.","specific_domain":"","methods":["reinforcement_learning","entropic_objective","puct_search","lora_fine_tuning","importance_sampling","llm_as_policy","llm_code_generation","evolutionary_search"],"problems":["erdos_minimum_overlap_problem","autocorrelation_inequalities","gpu_kernel_optimization","triangular_matrix_multiplication","multi_head_latent_attention","automated_algorithm_design"],"problem_short":"Discovery Problem","benchmarks":["Erdős’ Minimum Overlap Problem","Autocorrelation Inequalities (First)","Autocorrelation Inequalities (Second)","Circle Packing (n=26)","Circle Packing (n=32)","GPUMode TriMul Competition (A100)","GPUMode TriMul Competition (H100)","GPUMode TriMul Competition (B200)","GPUMode TriMul Competition (AMD MI300X)","GPUMode DeepSeek MLA Competition (AMD MI300X)","AtCoder Heuristic Contest 039 (ahc039)","AtCoder Heuristic Contest 058 (ahc058)","OpenProblems Denoising Benchmark (PBMC)","OpenProblems Denoising Benchmark (Tabula Muris Senis Lung)"],"baselines":["Best Human","AlphaEvolve [50]","AlphaEvolve V2 [14]","ThetaEvolve [78]","OpenEvolve [61]","Best-of-25600","ShinkaEvolve [37]","ALE-Agent [27]","MAGIC [75]","ALRA [40]"],"vs_baselines":{"Erdős’ Minimum Overlap Problem":"-0.0126% vs AlphaEvolve [50]","Autocorrelation Inequality 1":"-0.0179% vs ThetaEvolve [78]","Autocorrelation Inequality 2":"+0.197% vs AlphaEvolve V2 [14]","TriMul H100":"-15.31% vs 1st human","TriMul A100":"-51.48% vs 1st human","TriMul B200":"-12.00% vs 1st human","TriMul AMD MI300X":"-38.17% vs 1st human","MLA-Decode AMD MI300X":"+0.92% vs 1st human (not statistically significant)","AtCoder Heuristic Contest 039":"+0.011% vs 1st human","AtCoder Heuristic Contest 058":"+0.0048% vs ALE-Agent [27]","Denoising PBMC":"+1.43% vs OpenEvolve [61]","Denoising Tabula":"+2.82% vs OpenEvolve [61]"},"novelty_type":"combinatorial_novelty","closest_prior":"ThetaEvolve [78]","framework_lineage":"thetaevolve","llm_model":"gpt-oss-120b","code_url":"https://github.com/test-time-training/discover","new_benchmark":false,"confidence_results":"hi"},{"id":"2511.23473","title":"ThetaEvolve: Test-time Learning on Open Problems","authors":["Yiping"],"affiliations":"Microsoft, University of Washington, Carnegie Mellon University, University of Wisconsin-Madison, University of California, San Diego","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-11-28","priority":8.86,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly implements 'RL-infused evolution'—a primary focus of our research profile—and demonstrates that training on the dynamic evolutionary trajectory allows an 8B model to outperform Gemini-Pro ensembles. It provides a concrete, successful recipe for integrating GRPO with AlphaEvolve, which we must replicate immediately.","relevance":{"methodological":10,"problem":9,"inspirational":9},"brief":"ThetaEvolve integrates test-time reinforcement learning (GRPO) directly into an AlphaEvolve-style loop, allowing a single 8B model to learn from its own successful mutations and achieve new SOTA bounds on Circle Packing and Autocorrelation inequalities. The results are rigorous, showing that RL applied to the *dynamic* environment (sampling from the evolving database) vastly outperforms RL on static prompts or pure inference search. The most stealable insight is the 'lazy penalty' mechanism—penalizing semantically equivalent code or stagnation—which forces the RL policy to learn genuine exploration strategies rather than memorization. This is a blueprint for the 'RL-infused evolution' milestone in our AlgoEvo roadmap.","specific_domain":"mathematical_discovery","methods":["program_evolution","reinforcement_learning","grpo","llm_code_generation","llm_as_heuristic","llm_in_the_loop","evolution_of_heuristics","program_synthesis"],"problems":["mathematical_discovery","open_mathematical_optimization","circle_packing","autocorrelation_inequalities","hadamard_matrix","geometric_problems"],"problem_short":"OMOP-PE","benchmarks":["CirclePacking-T","FirstAutoCorrIneq","SecondAutoCorrIneq","ThirdAutoCorrIneq","HadamardMatrix"],"baselines":["AlphaEvolve","ShinkaEvolve","ThetaEvolve w/o RL","RL with static environment","Format reward baseline"],"vs_baselines":{"AlphaEvolve":"ThetaEvolve improves best-known bounds on Circle Packing (2.6359857 vs 2.63586276) and First Autocorrelation Inequality (1.503133 vs 1.503164).","ShinkaEvolve":"ThetaEvolve improves best-known bound on Circle Packing (2.6359857 vs 2.63598283).","ThetaEvolve w/o RL":"ThetaEvolve w/ RL consistently outperforms inference-only runs across all tasks (e.g., CirclePacking-T best 2.6359857 vs 2.6359834 for Distill-Qwen3-8B).","RL with static environment":"Performs much worse than ThetaEvolve w/ RL and even worse than ThetaEvolve w/o RL.","Format reward baseline":"Ineffective and performs worse than pure inference."},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaEvolve","framework_lineage":"alphaevolve","llm_model":"DeepSeek-R1-0528-Qwen3-8B","code_url":"https://github.com/ypwang61/ThetaEvolve","new_benchmark":false,"confidence_results":"lo"},{"id":"2602.16038","title":"Heuristic Search as Language-Guided Program Optimization","authors":["Mingxin"],"affiliations":"Massachusetts Institute of Technology","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-17","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a structural advance in LLM-based evolutionary search by replacing textual reflection with an 'Executable Analyst' that writes code to diagnose solver states. This directly addresses our focus on 'better signal for search' and 'observability' in AlgoEvo, offering a concrete way to improve upon ReEvo-style reflection.","relevance":{"methodological":9,"problem":10,"inspirational":9},"brief":"LaGO decomposes automated heuristic design into three explicit modules: evaluation, a code-writing 'Analyst' (backward pass), and a diversity-aware 'Generator' (update), while co-evolving constructive and refinement heuristics. The authors demonstrate significant gains (+0.17 QYI) on PDPTW and Crew Pairing against ReEvo and EoH, showing that joint optimization of initialization and improvement prevents local optima. The critical takeaway is the 'Analyst' module: instead of asking the LLM for text critiques, they ask it to write Python feature extraction functions to statistically characterize solution quality—a technique we should immediately adopt to upgrade our fitness signals in AlgoEvo.","specific_domain":"","methods":["llm_as_heuristic","llm_code_generation","llm_evolutionary_search","llm_in_the_loop","llm_as_evaluator","evolution_of_heuristics","program_synthesis","lago"],"problems":["combinatorial_optimization","pickup_and_delivery_problem_with_time_windows","airline_crew_pairing_problem","technology_mapping_problem","intra_operator_parallelism_scheduling","traveling_salesman_problem"],"problem_short":"AHD","benchmarks":["HeuriGym","Pickup and Delivery Problem with Time Windows (PDPTW)","Airline Crew Pairing Problem (CPP)","Technology Mapping Problem","Intra-Operator Parallelism Scheduling (IOPDDL)","Traveling Salesman Problem (TSP)"],"baselines":["HeuriGen (Chen et al., 2025)","EoH (Liu et al., 2024)","ReEvo (Ye et al., 2024)","LLM-LNS (Ye et al., 2025)","EoH-I","ReEvo-I","LLM-LNS-I"],"vs_baselines":{"PDPTW":"+0.172 QYI on test set vs ReEvo-I","Crew Pairing":"+0.002 QYI on test set vs LLM-LNS-I","Techno Mapping":"+0.014 QYI on test set vs LLM-LNS","Intra-op":"+0.094 QYI on test set vs ReEvo-I","TSP":"Achieved best results on 3 of 6 instances (rd100, pr124, u159) and second best on 2 others (kroA150, kroB200) compared to EoH, ReEvo, LLM-LNS"},"novelty_type":"combinatorial_novelty","closest_prior":"EoH (Liu et al., 2024)","framework_lineage":"lago","llm_model":"Gemini-3-Flash","code_url":null,"new_benchmark":false,"confidence_results":"lo"},{"id":"2602.02919","title":"DeltaEvolve: Accelerating Scientific Discovery through Momentum-Driven Evolution","authors":["Jiachen"],"affiliations":"Microsoft, The Ohio State University","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-02","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper proposes a concrete architectural fix (Semantic Deltas) for the context bottleneck in AlphaEvolve, a core method we use. The ablation study demonstrating that 'context selection dominates scalar feedback' challenges our current assumption that precise reward signals are the primary driver of evolution.","relevance":{"methodological":9,"problem":10,"inspirational":9},"brief":"DeltaEvolve replaces the standard full-code history in evolutionary search with 'semantic deltas'—structured text summaries capturing the 'from/to' logic of modifications and their hypotheses. Across 5 domains (including BBOB and Symbolic Regression), they demonstrate superior objective scores over AlphaEvolve while reducing token consumption by ~37%. The critical takeaway is the 'Progressive Disclosure' mechanism: treating history as a momentum vector (deltas) rather than a state archive (snapshots) allows us to fit a deeper evolutionary trajectory into the context window. We should immediately test their 'Delta Plan' prompt structure in AlgoEvo to improve sample efficiency and reduce costs.","specific_domain":"","methods":["llm_evolutionary_search","llm_code_generation","llm_as_heuristic","expectation_maximization","semantic_delta","multi_level_database","progressive_disclosure","map_elites"],"problems":["black_box_optimization","hexagon_packing","symbolic_regression","pde_solver","efficient_convolution","heuristic_evolution"],"problem_short":"LLM-driven Program Evolution","benchmarks":["BBOB (Black-Box Optimization Benchmarking) suite","Hexagon Packing (N=11)","Symbolic Regression (Nonlinear Harmonic Oscillator)","PDE Solver (2D Poisson Equation)","Efficient Convolution (2D kernel)"],"baselines":["Parallel Sampling","Greedy Refine","AlphaEvolve (Novikov et al., 2025)","OpenEvolve (Sharma, 2025)"],"vs_baselines":{"Parallel Sampling":"DeltaEvolve achieves significantly higher scores (e.g., +557.7% on Blackbox Optimization) and lower token consumption (e.g., -64.4% on Blackbox Optimization).","Greedy Refine":"DeltaEvolve achieves significantly higher scores (e.g., +20.68% on Blackbox Optimization) and lower token consumption (e.g., -30.0% on Blackbox Optimization).","AlphaEvolve":"DeltaEvolve achieves average +2.16% higher score and -30.91% lower token consumption across 5 tasks."},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaEvolve","framework_lineage":"alphaevolve","llm_model":"gpt-5-mini, o3-mini, gemini-2.5-flash-lite, gemini-2.5-flash","code_url":null,"new_benchmark":false,"confidence_results":"lo"},{"id":"2512.24077","title":"LoongFlow: Directed Evolutionary Search via a Cognitive Plan-Execute-Summarize Paradigm","authors":["Chunhui"],"affiliations":"","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-12-30","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly addresses our primary bottleneck in AlgoEvo: the inefficiency of 'blind' LLM mutations. It successfully integrates a ReAct-style cognitive loop (Plan-Execute-Summarize) into the evolutionary cycle, using lineage-based memory to guide mutations. The results on AlphaEvolve benchmarks explicitly outperform our current baselines (OpenEvolve/ShinkaEvolve) by 60% in efficiency.","relevance":{"methodological":9,"problem":10,"inspirational":9},"brief":"LoongFlow replaces the standard stochastic mutation operator in LLM evolutionary search with a 'Plan-Execute-Summarize' (PES) cognitive loop. Instead of random code changes, a Planner retrieves the 'intent' and 'summary' of the parent solution's lineage to generate a directed hypothesis, which is then executed and summarized for the next generation. The authors demonstrate a 60% reduction in evaluations and a 100% success rate on AlphaEvolve tasks where standard methods fail or stagnate. The critical takeaway is the 'Lineage-Based Context Retrieval' mechanism: explicitly passing the parent's plan and retrospective summary to the child allows for directed rather than random walks in the search space. We must implement this PES loop in AlgoEvo immediately to fix our sample efficiency issues.","specific_domain":"operator_discovery","methods":["plan_execute_summarize","hybrid_evolutionary_memory","multi_island_model","map_elites","adaptive_boltzmann_selection","lineage_based_context_retrieval","polymorphic_execution_strategies","local_verification_loop"],"problems":["algorithm_discovery","operator_discovery","ml_pipeline_optimization","mathematical_problems","circle_packing"],"problem_short":"Algorithmic Discovery","benchmarks":["AlphaEvolve Suite","MLEBench"],"baselines":["OpenEvolve","ShinkaEvolve"],"vs_baselines":{"OpenEvolve":"Up to 60% improvement in evolutionary efficiency, significantly outperformed on AlphaEvolve Suite (e.g., Autocorrelation II: 0.9027 vs 0.8962), 100% success rate vs 33% on Circle Packing (Square), broke theoretical barrier vs failed on high-difficulty tasks.","ShinkaEvolve":"Failed to break 0.99 barrier on Circle Packing (Square), failed to reach score of 1.0 on high-difficulty tasks."},"novelty_type":"combinatorial_novelty","closest_prior":"OpenEvolve","framework_lineage":"alphaevolve","llm_model":"DeepSeek-r1-0528, Gemini-3-Pro-Preview, Gemini-3.0-flash, Claude-Opus-4.5","code_url":"https://github.com/baidu-baige/LoongFlow","new_benchmark":false,"confidence_results":"hi"},{"id":"2510.27176","title":"Glia: A Human-Inspired AI for Automated Systems Design and Optimization","authors":["Pouya"],"affiliations":"MIT CSAIL, Independent Researcher","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2025-11-17","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly attacks the core limitations of AlphaEvolve and FunSearch (black-box mutation) by introducing a white-box, hypothesis-driven multi-agent workflow. It achieves superior sample efficiency and applies this directly to our exact domain of LLM serving and GPU scheduling, making it a mandatory read for the AlgoEvo and GPUSched projects.","relevance":{"methodological":9,"problem":9,"inspirational":9},"brief":"Glia replaces black-box LLM evolutionary search (like AlphaEvolve) with a multi-agent workflow (Researcher + Supervisor) that instruments simulators, analyzes telemetry, forms hypotheses, and writes interpretable system algorithms for LLM serving. The results are backed by strong empirical numbers; it outperforms OpenEvolve, FunSearch, and EoH by 1.3-1.7x in mean response time using significantly fewer simulations (massive sample efficiency gains), and the results transfer to a real vLLM cluster. The single most useful takeaway is shifting from pure code-level mutation to 'idea-level' evolution: forcing the LLM to analyze simulation logs and write a chain-of-thought hypothesis before generating code, guided by a Supervisor agent that prevents stagnation. This is a direct threat and massive inspiration for AlgoEvo; it proves that for systems optimization, agentic reasoning with observability beats blind evolutionary search, and we should immediately test their log-analysis loop and Multi-Context parallel sampling strategy.","specific_domain":"llm_inference_serving_optimization","methods":["llm_as_heuristic","llm_code_generation","llm_in_the_loop","llm_research_agent","multi_agent_system","iterative_refinement","hypothesis_testing","empirical_feedback"],"problems":["llm_inference_serving","request_routing","batch_scheduling","auto_scaling","resource_allocation","gpu_scheduling"],"problem_short":"LLM System Design & Optimization","benchmarks":["vidur simulator","ShareGPT workload"],"baselines":["Evolution of Heuristics (EoH)","FunSearch","OpenEvolve (AlphaEvolve)","Round-Robin","Least-Loaded Queue (LLQ)","Least Outstanding Requests (LOR)","Human Expert-designed heuristic","vLLM/Sarathi batch scheduler","Off-the-shelf autoscaler","Standard serving systems"],"vs_baselines":{"LLQ":"2.2x lower mean RT (routing), 4.5x lower slowdown (real system routing)","OpenEvolve":"1.6x lower mean RT (routing), 1.6x better RT (MCG)","EoH":"1.7x better RT (MCG)","FunSearch":"1.3x better RT (MCG)","Human Expert":"matches performance in 2 hours vs 2 weeks (routing), 4.6x improvement in P90 TTFT (new workload)","vLLM/Sarathi batch scheduler":"25% reduction in end-to-end delay (batch scheduling)","Off-the-shelf autoscaler":"13% reduction in GPU cost (autoscaling)","Standard serving systems":"40% reduction in GPUxhours (full stack)"},"novelty_type":"paradigm_shift","closest_prior":"AlphaEvolve","framework_lineage":"","llm_model":"OpenAI o3","code_url":"https://github.com/naman-dixit00/University-of-Massachusetts-Seminar-Series-","new_benchmark":false,"confidence_results":"hi"},{"id":"2510.11121","title":"Refining Hybrid Genetic Search for CVRP via Reinforcement Learning-Finetuned LLM","authors":["Rongjie"],"affiliations":"Nanyang Technological University, Singapore, Singapore Management University, Singapore, Nanjing University of Information Science and Technology, China","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-10-13","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper validates a critical hypothesis for our AlgoEvo work: that RL-finetuning small models on code execution feedback outperforms prompting SOTA models (GPT-4o) for heuristic discovery. It provides a concrete, successful recipe for 'RL-infused evolution' applied to our exact problem domain (HGS for CVRP).","relevance":{"methodological":9,"problem":10,"inspirational":9},"brief":"Zhu et al. fine-tune a Qwen-14B model using Reinforcement Learning (DAPO) to generate C++ crossover operators for the state-of-the-art HGS solver. Unlike typical prompting papers, they demonstrate that a small, specialized model can improve upon expert-designed components in a highly optimized solver, achieving superior results on CVRPLIB (up to 1000 nodes) where GPT-4o fails. The most stealable insight is their **AST-based anti-plagiarism reward**, which penalizes the model for generating code structurally identical to the prompt examples, effectively forcing exploration and preventing mode collapse—a technique we should immediately adopt for our evolutionary search agents. This confirms we should pivot from pure prompting to RL-finetuning for our code-generation agents.","specific_domain":"cvrp","methods":["genetic_algorithm","hgs","reinforcement_learning","rl_dapo","llm_as_heuristic","llm_code_generation","llm_fine_tuned","llm_rl_trained"],"problems":["cvrp","combinatorial_routing","operator_discovery","heuristic_evolution"],"problem_short":"CVRP","benchmarks":["CVRPLIB X instances"],"baselines":["HGS-PyVRP800","HGS-PyVRP1000","OR-Tools","LKH","POMO","MTPOMO","MVMoE","RF-POMO","RF-MoE-L","AM","DeepACO","NeuroLKH","NeuOpt","MCTS-AHD","ReEvo","GPT4o800","GPT4o1000","GPT-o3800","GPT-o31000","GPT-o4-mini800","GPT-o4-mini1000"],"vs_baselines":{"HGS-PyVRP1000":"Outperforms by 0.03-0.08% gap across all instance sizes (n=100-1000)","HGS-PyVRP800":"Slightly worse on n<200 (+0.08% gap), but better on n>=200 (up to -0.05% gap)","GPT4o/o3/o4-mini":"Outperforms, as these LLMs match HGS-PyVRP performance but RFTHGS is superior","OR-Tools":"Significantly outperforms (RFTHGS gap < 3% vs OR-Tools gap > 4%)","LKH":"Significantly outperforms (RFTHGS gap < 3% vs LKH gap > 1%)","NCO methods":"Significantly outperforms (e.g., RFTHGS gap < 3% vs POMO > 13%)","Prompting-Based LLM methods":"Significantly outperforms (e.g., RFTHGS gap < 3% vs ReEvo > 72%)"},"novelty_type":"combinatorial_novelty","closest_prior":"HGS-PyVRP","framework_lineage":"hgs","llm_model":"Qwen-14B reasoning LLM","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2508.11850","title":"EvoCut: Strengthening Integer Programs via Evolution-Guided Language Models","authors":["M."],"affiliations":"Huawei Technologies Canada, University of British Columbia, University of Toronto","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-08-16","priority":8.81,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper appears to be a direct collision with your active project 'EvoCut' (same name, same methodology). It successfully demonstrates that LLMs can generate effective MILP cuts using empirical verification rather than formal proofs, a strategy we must evaluate immediately.","relevance":{"methodological":9,"problem":10,"inspirational":9},"brief":"Yazdani et al. introduce EvoCut, an evolutionary framework where LLMs generate Python code for MILP cuts, filtered by a 'usefulness check' (does it cut the current LP relaxation?) and an 'empirical validity check' (does it preserve known integer optima?). They report 17-57% gap reductions on TSPLIB and JSSP compared to Gurobi defaults, backed by strong ablation studies on the evolutionary operators. **Key Takeaway:** The reliance on 'acceleration cuts'—constraints verified empirically on small datasets rather than formally proven—bypasses the bottleneck of automated theorem proving while still delivering valid speedups. We should immediately adopt their 'LP separation' check as a cheap, high-signal reward for our own evolutionary search loops.","specific_domain":"","methods":["evolutionary_algorithm","llm_as_heuristic","llm_code_generation","llm_in_the_loop","evolution_of_heuristics","funsearch","program_synthesis","cutting_planes"],"problems":["MILP_general","TSP","MCND","CWLP","job_shop_scheduling","tiling_problem"],"problem_short":"MILP Cut Generation","benchmarks":["TSPLIB","CommaLAB R MCND instances","OR-LIB CWLP instances","Taillard JSSP benchmark","IMO 2025 P6 tiling problem"],"baselines":["Gurobi Optimizer without cuts","Cuts produced solely by the initializer agent"],"vs_baselines":{"Gurobi Optimizer without cuts":"TSP: 57.4% gap reduction, 74% time saving for 10% gap; MCND: 17.1% gap reduction; CWLP: 46.2% gap reduction; JSSP: 37.3% gap reduction"},"novelty_type":"combinatorial_novelty","closest_prior":"Romera-Paredes et al. 2024","framework_lineage":"funsearch","llm_model":"DeepSeek-R1","code_url":"https://github.com/milad1378yz/EvoCut","new_benchmark":false,"confidence_results":"hi"},{"id":"2601.21008","title":"Solver-in-the-Loop: MDP-Based Benchmarks for Self-Correction and Behavioral Rationality in Operations Research","authors":["Ruicheng"],"affiliations":"Massachusetts Institute of Technology, Alibaba Group","category":"Generative AI for OR","subdomain":"rl_for_opt_modeling","date":"2026-02-08","priority":8.78,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper provides a concrete blueprint for 'RL-infused evolution' in OR by successfully applying GRPO and Process Reward Models (PRM) to optimization tasks. It demonstrates that small, specialized models trained with solver feedback (IIS) outperform frontier models, validating a shift from prompting to RL-finetuning for our AlgoEvo work.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"Ao et al. introduce a framework for iterative OR model debugging that trains an 8B model using Group Relative Policy Optimization (GRPO) and a Process Reward Model (PRM) to outperform GPT-4o-mini. They utilize Gurobi's Irreducible Infeasible Subsystem (IIS) not just as text feedback, but as a dense reward signal (IIS size reduction) for the PRM, achieving a 95.3% recovery rate versus 86.2% for frontier APIs. **Key Takeaway:** We should steal their PRM construction method—specifically using solver diagnostics (like IIS reduction or compiler error counts) as dense step-level rewards—and their 'faithfulness penalty' to prevent overfitting in our evolutionary search. This is a direct validation of RLVR (Reinforcement Learning with Verifiable Rewards) for OR, proving it superior to large-scale prompting.","specific_domain":"","methods":["llm_as_heuristic","llm_code_generation","llm_in_the_loop","supervised_learning","rl_ppo","grpo","curriculum_learning","process_reward_model"],"problems":["llm_evaluation_for_or","infeasibility_diagnosis","newsvendor_problem","llm_self_correction","behavioral_bias_mitigation","linear_programming_debugging"],"problem_short":"OR Debugging & Newsvendor","benchmarks":["OR-Debug-Bench","OR-Bias-Bench"],"baselines":["o4-mini","claude-sonnet-4","gpt-5.2-chat","Llama-3.3-70B","DeepSeek-R1","SFT-only models"],"vs_baselines":{"Llama-3.1-8B-GRPO":"+11.1% RR@5 (97.3% vs 86.2% for best API)","Qwen3-8B-GRPO":"+14.6% DA (62.4% vs 47.8% for o4-mini) and 1.4-2.8x faster repair (2.25 steps vs 3.15-5.08 steps for API models)","Qwen3-8B-Curriculum":"-9.6% ID→OOD bias drift (only negative drift among models evaluated), reducing systematic bias by 48% (from 20.0% to 10.4%)"},"novelty_type":"combinatorial_novelty","closest_prior":"CorrectBench","framework_lineage":"grpo","llm_model":"Qwen3-8B-Instruct","code_url":null,"new_benchmark":true,"confidence_results":"hi"},{"id":"2505.22954","title":"Darwin Godel Machine: Open-Ended Evolution of Self-Improving Agents","authors":["Jenny"],"affiliations":"Sakana AI, Vector Institute, University of British Columbia, Canada CIFAR AI Chair","category":"LLMs for Algorithm Design","subdomain":"llm_agents_discovery","date":"2025-09-26","priority":8.76,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper successfully demonstrates 'Evolving the Evolver'—a core goal of our AlgoEvo project—by enabling agents to modify their own source code rather than just prompts. It provides a concrete, empirically validated blueprint for self-referential evolutionary search that we can immediately adapt.","relevance":{"methodological":10,"problem":8,"inspirational":10},"brief":"DGM implements a population-based evolutionary loop where agents modify their own Python source code (tools, memory, flow) to improve performance on coding benchmarks, rather than just optimizing prompts or parameters. Results are strong and verified: it boosts a base agent from 20% to 50% on SWE-bench Verified, matching handcrafted SoTA, with ablations proving the necessity of the population archive (open-endedness) over single-lineage hill climbing. **Key Takeaway:** The 'self-diagnosis' mechanism—feeding execution logs to a model to propose specific *architectural* code changes (e.g., implementing a 'str_replace' tool to fix granular editing errors)—is the exact mechanism we need to implement for evolving our heuristic searchers. This validates that LLM-driven code evolution is viable for complex logic improvement, not just toy tasks.","specific_domain":"software_engineering_tasks","methods":["darwin_godel_machine","open_ended_evolution","evolution_of_heuristics","llm_code_generation","llm_as_heuristic","llm_as_evaluator","llm_in_the_loop","program_synthesis"],"problems":["software_engineering_tasks","code_generation","automated_algorithm_design","heuristic_evolution","llm_hallucination_mitigation"],"problem_short":"Self-Improving AI","benchmarks":["SWE-bench Verified","Polyglot"],"baselines":["DGM without self-improving agents","DGM without open-ended exploration","OpenHands + CodeAct v2.1 (claude-3-5-sonnet-20241022)","Aider","DGM Greedy"],"vs_baselines":{"DGM without self-improving agents":"outperforms, gains taper off quickly","DGM without open-ended exploration":"outperforms, makes very little progress","OpenHands + CodeAct v2.1 (claude-3-5-sonnet-20241022)":"DGM 50.0% vs SoTA 51.0% on 200 tasks (comparable)","Aider":"DGM 30.7% vs Aider (approx 15-18% on pass@1) (DGM far surpasses)","DGM Greedy":"DGM 50.0% (SWE-bench) / 38.0% (Polyglot) vs DGM Greedy 39.7% (SWE-bench) / 30.0% (Polyglot)"},"novelty_type":"combinatorial_novelty","closest_prior":"Robeyns et al., 2025","framework_lineage":"dgm","llm_model":"Claude 3.5 Sonnet (New), o3-mini, OpenAI o1","code_url":"https://github.com/jennyzzt/dgm","new_benchmark":false,"confidence_results":"hi"},{"id":"2601.21372","title":"NEMO: Execution-Aware Optimization Modeling via Autonomous Coding Agents","authors":["Yang"],"affiliations":"Carnegie Mellon University, C3 AI","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2026-01-29","priority":8.71,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a 'Simulator-Optimizer' asymmetric validation loop that solves the ground-truth-free evaluation problem in code generation. This architecture directly addresses our need for better fitness signals in AlgoEvo and robust modeling in OR-Bench, offering a concrete pattern to replace brittle unit tests.","relevance":{"methodological":9,"problem":9,"inspirational":9},"brief":"NEMO achieves SOTA on 8/9 optimization benchmarks by deploying autonomous coding agents that generate both a declarative optimizer (solver code) and an imperative simulator (verification code). The key innovation is using the simulator to validate the optimizer's results in a closed loop, detecting logical errors without ground truth—a technique that beats fine-tuned models like SIRL by up to 28%. The most stealable insight is this asymmetric validation: imperative Python simulation is often less error-prone than declarative constraint formulation, making it a robust 'critic' for generated solvers. This is immediately applicable to our OR-Bench and AlgoEvo projects for generating reliable reward signals.","specific_domain":"optimization_model_synthesis","methods":["llm_code_generation","llm_in_the_loop","llm_prompt_optimization","in_context_learning","autonomous_coding_agents","minimum_bayes_risk_decoding","self_consistency","asymmetric_validation"],"problems":["optimization_model_synthesis","linear_programming","mixed_integer_linear_programming","non_linear_programming","second_order_cone_programming","knapsack"],"problem_short":"Automated Optimization Modeling","benchmarks":["OptiBench","OptMATH-Bench","NL4OPT","NLP4LP","BWOR","IndustryOR","MAMO-Easy","MAMO-Complex","ComplexOR"],"baselines":["OptimAI","OptiMUS","OR-LLM-Agent","CoE","OptMATH","ORLM","LLMOPT","SIRL"],"vs_baselines":{"OptimAI":"+8.1% on OptiBench","OptiMUS":"+19.6% on NL4OPT, +9.4% on NLP4LP, +11.1% on ComplexOR","OR-LLM-Agent":"+22.5% on NL4OPT, 0% on BWOR, +27.0% on IndustryOR, +1.2% on MAMO-Easy, +20.4% on MAMO-Complex","CoE":"+34.2% on NL4OPT, +28.3% on NLP4LP, +39.7% on ComplexOR","OptMATH":"+24.3% on OptiBench, +31.0% on OptMATH-Bench, +2.5% on NL4OPT, -6.5% on MAMO-Easy, +17.9% on MAMO-Complex","ORLM":"+11.9% on NL4OPT, +25.0% on IndustryOR, -1.8% on MAMO-Easy","LLMOPT":"+24.0% on OptiBench, +25.7% on OptMATH-Bench, +19.0% on IndustryOR, -13.8% on MAMO-Complex, +5.1% on ComplexOR","SIRL":"+23.0% on OptiBench, +19.9% on OptMATH-Bench"},"novelty_type":"combinatorial_novelty","closest_prior":"OptimAI","framework_lineage":"nemo","llm_model":"OpenAI o3, Claude 3.7 Sonnet, Qwen3-Embedding-8B","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2509.07367","title":"Autonomous Code Evolution Meets NP-Completeness","authors":["Cunxi"],"affiliations":"NVIDIA Research, University of Maryland","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-09-09","priority":8.71,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper demonstrates that LLM evolutionary search can scale from isolated kernels (AlphaEvolve) to full repository maintenance and innovation, beating human SOTA on the canonical NP-complete problem. It introduces a 'self-evolving rule system' that solves the stability/memory bottleneck we face in AlgoEvo, making it a blueprint for our next architecture update.","relevance":{"methodological":9,"problem":9,"inspirational":10},"brief":"SATLUTION extends LLM evolutionary search to full-scale C++ repositories, autonomously evolving SAT solvers that outperform 2025 human competition winners using only 2024 training data. The results are highly rigorous, backed by 90k CPU hours of distributed evaluation and strict correctness proofs (DRAT), showing a clear monotonic improvement trajectory. The single most stealable insight is the **self-evolving rule system**: the agent autonomously updates a persistent set of markdown constraints (e.g., forbidden patterns, testing protocols) based on post-cycle failure analysis, effectively creating 'institutional memory' that prevents regression in long-horizon search. We must implement this meta-learning loop in AlgoEvo immediately to move beyond single-file optimization.","specific_domain":"boolean_satisfiability","methods":["llm_evolutionary_search","llm_code_generation","llm_in_the_loop","program_synthesis","self_improving_search","evolution_of_heuristics","conflict_driven_clause_learning","multi_armed_bandit"],"problems":["boolean_satisfiability","np_complete_problem","combinatorial_optimization","heuristic_evolution","algorithm_discovery"],"problem_short":"SAT","benchmarks":["SAT Competition 2024 benchmark","SAT Competition 2025 benchmark"],"baselines":["AE kissat2025 MAB (Winner SC25)","kissat-public (2nd place SC25)","kissat-sc2024 (Winner SC24)","kissat-mab-dc","kissat-mab-binary","BreakID-Kissat","AMSAT","cadical public","CaDiCaL","Kissat MAB Binary","Kissat MAB ESA"],"vs_baselines":{"AE kissat2025 MAB (Winner SC25)":"SATLUTION attained the lowest PAR-2, outperforming the top-2 2025 winning solvers on SAT 2025 benchmark. Solved 347, 345, and 344 instances vs 334 for AE kissat2025 MAB on SAT 2025 benchmark. Substantially outperformed all original 2024 solvers and even surpassed the 2025 champion when run on the 2024 instances.","kissat-public (2nd place SC25)":"SATLUTION attained the lowest PAR-2, outperforming the top-2 2025 winning solvers on SAT 2025 benchmark. Solved 347, 345, and 344 instances vs 331 for kissat-public on SAT 2025 benchmark.","kissat-sc2024 (Winner SC24)":"SATLUTION achieves the lowest overall PAR-2 score, substantially outperforming all original 2024 solvers and even surpassing the 2025 champion when run on the 2024 instances."},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaEvolve: A coding agent for scientific and algorithmic discovery","framework_lineage":"alphaevolve","llm_model":"Claude models","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2601.21239","title":"TIDE: Tuning-Integrated Dynamic Evolution for LLM-Based Automated Heuristic Design","authors":["Chentong"],"affiliations":"","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-01-29","priority":8.66,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper proposes a concrete architectural fix for 'numerical blindness' in LLM evolutionary search by embedding a Differential Evolution layer. It directly addresses our sample efficiency and precision bottlenecks in AlgoEvo.","relevance":{"methodological":9,"problem":10,"inspirational":8},"brief":"TIDE introduces a nested evolutionary framework that strictly decouples algorithmic structure generation (via LLM) from numerical parameter tuning (via Differential Evolution), managed by a Tree Similarity Edit Distance (TSED) guided island model. Results on 9 COPs (TSP, BPP, etc.) show it consistently outperforms ReEvo and EoH, primarily because the DE layer optimizes constants at zero token cost, preventing the discard of structurally sound but poorly tuned heuristics. The critical takeaway is the necessity of a gradient-free tuning layer for LLM-generated code; relying on LLMs for numerical constants is inefficient and imprecise. We should immediately implement a similar parameter-tuning inner loop in our AlgoEvo framework.","specific_domain":"","methods":["evolutionary_algorithm","island_model_ea","co_evolution","differential_evolution","llm_as_heuristic","llm_code_generation","ucb","multi_armed_bandit"],"problems":["heuristic_design","tsp","knapsack","bin_packing","assignment_problem","cvrp"],"problem_short":"AHD","benchmarks":["TSP","KP","online BPP","ASP","TSP GLS","TSP KGLS","CVRP","OP","MKP","offline BPP","DPP","Mountain Car-v0","TSPLIB"],"baselines":["Greedy","POMO","EoH","ReEvo","HSEvo","MCTS-AHD","LKH3","OR-Tools","NeuOpt","DeepACO","First Fit","Best Fit"],"vs_baselines":{"EoH":"TIDE achieves -7.35% gap on Constructive TSP N=50 (4.76% vs 12.11%) and -0.6% on Constructive KP N=50 (0.04% vs 0.60%)","ReEvo":"TIDE achieves -3.51% gap on Constructive TSP N=50 (4.76% vs 8.27%) and -0.17% on Constructive KP N=50 (0.04% vs 0.21%)","HSEvo":"TIDE achieves -3.28% gap on Constructive TSP N=50 (4.76% vs 8.04%) and -0.13% on Constructive KP N=50 (0.04% vs 0.17%)","MCTS-AHD":"TIDE achieves -3.43% gap on Constructive TSP N=50 (4.76% vs 8.19%) and -0.13% on Constructive KP N=50 (0.04% vs 0.17%)","POMO":"TIDE outperforms by +2.08% on Constructive KP N=50 (0.04% vs 2.12%)","NeuOpt":"TIDE outperforms by +0.278% on Improvement TSP GLS N=100 (0.026% vs 0.304%)","DeepACO":"TIDE outperforms by +0.04 on ACO TSP N=50 (5.80 vs 5.84)","Greedy":"TIDE outperforms by +22.58% on Constructive TSP N=50 (4.76% vs 22.62%)","First Fit":"TIDE outperforms by +1.44% on Online BPP 1k (3.33% vs 4.77%)","Best Fit":"TIDE outperforms by +1.69% on Online BPP 1k (3.33% vs 5.02%)"},"novelty_type":"combinatorial_novelty","closest_prior":"EoH","framework_lineage":"eoh","llm_model":"Qwen3-Max-2025-09-23","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2602.16928","title":"Discovering Multiagent Learning Algorithms with Large Language Models","authors":["Zun"],"affiliations":"Google DeepMind","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-18","priority":8.61,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This is a direct application of AlphaEvolve (your primary focus) by DeepMind that successfully discovers SOTA algorithms. It validates the evolutionary code search approach on complex iterative problems and provides concrete templates for evolving stateful, dynamic update rules.","relevance":{"methodological":10,"problem":8,"inspirational":9},"brief":"DeepMind applies AlphaEvolve to discover new variants of CFR and PSRO by evolving Python code for regret accumulation and meta-strategy solving. They identify VAD-CFR and SHOR-PSRO, which outperform human-designed SOTA (DCFR, PCFR+) on benchmarks like Leduc Poker and Liar's Dice; results are rigorous, using exact exploitability. The critical takeaway is the shift from evolving static functions to evolving **stateful classes** (e.g., tracking volatility via EWMA inside the accumulator), allowing the LLM to discover dynamic, adaptive schedules—a technique we should immediately port to AlgoEvo.","specific_domain":"imperfect_information_games","methods":["alphaevolve","llm_code_generation","llm_evolutionary_search","evolutionary_algorithms","program_synthesis","counterfactual_regret_minimization","policy_space_response_oracles","optimistic_regret_matching"],"problems":["multi_agent_reinforcement_learning","game_theory","imperfect_information_games","heuristic_evolution","kuhn_poker","leduc_poker"],"problem_short":"MARL-AD","benchmarks":["Kuhn Poker","Leduc Poker","Goofspiel","Liar's Dice"],"baselines":["CFR (Zinkevich et al., 2007)","CFR+ (Tammelin, 2014)","Linear CFR (LCFR)","Discounted CFR (DCFR) (Brown and Sandholm, 2019b)","Predictive CFR+ (PCFR+) (Farina et al., 2021)","Discounted Predictive CFR+ (DPCFR+) (Xu et al., 2024b)","Hyperparameter Schedule-powered PCFR variant HS-PCFR+(30) (Zhang et al., 2026)","Uniform","Nash equilibrium","AlphaRank (Muller et al., 2020)","Projected Replicator Dynamics (PRD) (Lanctot et al., 2017)","Regret Matching (RM)"],"vs_baselines":{"VAD-CFR":"outperforms state-of-the-art baselines like DPCFR+ on 3-player Kuhn Poker, Leduc Poker, and 4-card Goofspiel; matches or surpasses SOTA in 10 of 11 games","SHOR-PSRO":"achieves exploitability levels (< 10^-3) significantly faster than PRD or RM on Kuhn Poker; consistently matches or outperforms best-performing baselines on 3-player Leduc Poker; shows clear advantage on 6-sided Liar’s Dice; matches or surpasses SOTA in 8 of 11 games"},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaEvolve (Novikov et al., 2025)","framework_lineage":"alphaevolve","llm_model":"Gemini 2.5 pro","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2503.10721","title":"From Understanding to Excelling: Template-Free Algorithm Design through Structural-Functional Co-Evolution","authors":["Zhe"],"affiliations":"Princeton University, Nanyang Technological University, City University of Hong Kong, University of Science and Technology of China, The Hong Kong University of Science and Technology (Guangzhou)","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-03-13","priority":8.6,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly targets the primary bottleneck of our current research (FunSearch/EoH's reliance on fixed templates) by introducing a 'structural' evolution layer. It effectively proposes the next generation of the architecture we are currently building.","relevance":{"methodological":9,"problem":9,"inspirational":8},"brief":"Zhao et al. propose CAE, a framework that co-evolves algorithm structure (workflow/call graphs) alongside function implementations, aiming to eliminate the fixed templates required by SOTA methods like FunSearch and EoH. On TSP benchmarks, they report reducing optimality gaps by ~2-5% compared to ReEvo, and in quadratic optimization, the system autonomously discovered numerical stability fixes (e.g., replacing matrix inversion with solvers) that human baselines missed. The critical takeaway is the 'bi-dimensional co-evolution' strategy: explicitly maintaining and mutating a population of control flow graphs separate from the function bodies, which allows the system to escape the local optima imposed by a fixed human-designed harness. We must evaluate if this structural search approach can be integrated into AlgoEvo to automate our harness design.","specific_domain":"","methods":["llm_code_generation","llm_as_heuristic","llm_in_the_loop","evolutionary_algorithm","genetic_algorithm","evolution_of_heuristics","program_synthesis","hyper_heuristics"],"problems":["algorithm_discovery","heuristic_evolution","tsp","cvrp","quadratic_optimization","expensive_continuous_optimization"],"problem_short":"AAD","benchmarks":["ts225","eil51","d657","rat99","d493","kroA150","rl1889","kroB100","fl1577","u1817","kroC100","u724","d1655","ch130","pr264","bier127","pr299","pr226","lin318","fl417","pr439","TSP20","TSP50","TSP100","Quadratic Optimization"],"baselines":["GHPP [41]","ReEvo [4]","GA","GA+EOH [1]","GA+ReEvo [4]","ACO","ACO+EOH [1]","ACO+ReEvo [4]","KGLS [42]","KGLS+EOH","KGLS+ReEvo","IQN","SLIQN","LISR-1","LISR-k"],"vs_baselines":{"GHPP [41]":"CAE achieves significantly lower optimality gaps (e.g., 4.6% vs 7.7% on ts225, 3.5% vs 10.2% on eil51)","ReEvo [4]":"CAE achieves significantly lower optimality gaps (e.g., 4.6% vs 6.6% on ts225, 3.5% vs 6.5% on eil51)","GA":"CAE achieves higher optimality gaps (e.g., 6.6% vs 0.0% on TSP20, 10.3% vs 0.0% on TSP50)","GA+EOH [1]":"CAE achieves higher optimality gaps (e.g., 6.6% vs 1.9% on TSP20, 10.3% vs 2.3% on TSP50)","GA+ReEvo [4]":"CAE achieves higher optimality gaps (e.g., 6.6% vs 1.9% on TSP20, 10.3% vs 1.3% on TSP50)","ACO":"ACO+CAE achieves higher optimality gaps (e.g., 0.5% vs 0.0% on TSP20, 1.8% vs 0.0% on TSP50)","ACO+EOH [1]":"ACO+CAE achieves higher optimality gaps (e.g., 0.5% vs -0.7% on TSP20, 1.8% vs 0.8% on TSP50)","ACO+ReEvo [4]":"ACO+CAE achieves higher optimality gaps (e.g., 0.5% vs -0.2% on TSP20, 1.8% vs 0.3% on TSP50)","KGLS [42]":"KGLS+CAE achieves higher optimality gaps (e.g., 11.2% vs 0.0% on TSP20, 11.7% vs 0.0% on TSP50)","KGLS+EOH":"KGLS+CAE achieves higher optimality gaps (e.g., 11.2% vs 0.6% on TSP20, 11.7% vs -0.2% on TSP50)","KGLS+ReEvo":"KGLS+CAE achieves higher optimality gaps (e.g., 11.2% vs 0.2% on TSP20, 11.7% vs -1.0% on TSP50)","IQN":"LISR-k(CAE) shows faster convergence and better objective values, especially for ill-conditioned problems (e.g., optimal convergence within 50s for ξ=12, while IQN plateaus early).","SLIQN":"LISR-k(CAE) shows faster convergence and better objective values, especially for ill-conditioned problems (e.g., optimal convergence within 50s for ξ=12, while SLIQN plateaus early).","LISR-1":"LISR-k(CAE) shows faster convergence and better objective values, especially for ill-conditioned problems.","LISR-k":"LISR-k(CAE) shows faster convergence and better objective values, especially for ill-conditioned problems."},"novelty_type":"combinatorial_novelty","closest_prior":"Evolution of heuristics: Towards efficient automatic algorithm design using large language model","framework_lineage":"cae","llm_model":"","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2602.23413","title":"EvoX: Meta-Evolution for Automated Discovery","authors":["Shu"],"affiliations":"UC Berkeley, Stanford University, Bespoke Labs","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-26","priority":8.56,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"EvoX directly executes on our core objective of 'Evolving the Evolver' by introducing a meta-evolution loop that dynamically rewrites the search strategy based on population state. It empirically beats AlphaEvolve and ShinkaEvolve, making it an immediate threat and inspiration for AlgoEvo.","relevance":{"methodological":9,"problem":9,"inspirational":9},"brief":"EvoX introduces a two-level LLM-driven evolutionary framework that jointly evolves candidate solutions and the search strategies (parent selection rules, variation operators) used to generate them. The results are highly rigorous and backed by extensive numbers, demonstrating state-of-the-art performance across nearly 200 real-world optimization tasks (math, systems, Frontier-CS) and outperforming AlphaEvolve, OpenEvolve, and ShinkaEvolve. The single most useful takeaway is their use of a 'population state descriptor' combined with a sliding window stagnation detector; when progress stalls, EvoX prompts the LLM with this descriptor and a history of past strategies to generate a new, state-aware search policy (e.g., switching from free-form variation to UCB-guided structural variation). This paper is a mandatory read for us: it is a direct, high-quality implementation of our 'Evolving the Evolver' concept, and we should immediately steal their meta-evolution loop and state descriptor design to fix stagnation issues in AlgoEvo.","specific_domain":"","methods":["evolutionary_search","meta_evolution","llm_driven_optimization","llm_as_heuristic","llm_code_generation","map_elites","ucb_selection","local_refinement"],"problems":["automated_algorithm_design","heuristic_evolution","program_synthesis","circle_packing","heilbronn_problem","min_max_min_distance"],"problem_short":"Meta-Evolutionary Search","benchmarks":["Circle Packing","Circle Packing Rect","Heilbronn Convex","Heilbronn Triangle","MinMaxMinDist (n=16, d=2)","MinMaxMinDist (n=14, d=3)","Third Autocorr Ineq","Signal Processing","EPLB","PRISM","LLM-SQL","Cloudcast","Transaction Scheduling","Telemetry Repair","ALE-Bench-Lite","Frontier-CS","ARC-AGI-2"],"baselines":["AlphaEvolve","OpenEvolve","GEPA","ShinkaEvolve","CodeEvolve","ThetaEvolve","Human Best","AI Best","Random Search Strategy","Static Baseline","ALE-Agent"],"vs_baselines":{"AlphaEvolve":"matches or exceeds on 5/7 math tasks (e.g., Circle Packing, MinMaxMinDist)","OpenEvolve":"outperforms on 96% of math/system tasks, 24% mean / 34% median on Frontier-CS","GEPA":"outperforms on 96% of math/system tasks, 22% mean / 34% median on Frontier-CS","ShinkaEvolve":"outperforms on 96% of math/system tasks, 30% mean / 63% median on Frontier-CS","Human Best":"exceeds on all 6 system benchmarks (Gemini-3.0-Pro), matches/surpasses on math tasks","Static Baseline":"+34.1% final score on Signal Processing","ALE-Agent":"+8.3% average private score on ALE-Bench-Lite","CodeEvolve":"consistent advantages","ThetaEvolve":"consistent advantages"},"novelty_type":"paradigm_shift","closest_prior":"AlphaEvolve","framework_lineage":"","llm_model":"GPT-5, Gemini-3.0-Pro","code_url":"https://github.com/skydiscover-ai/skydiscover","new_benchmark":false,"confidence_results":"lo"},{"id":"2602.20133","title":"AdaEvolve: Adaptive LLM Driven Zeroth-Order Optimization","authors":["Mert"],"affiliations":"University of California, Berkeley, Bespoke Labs","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-23","priority":8.56,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a hierarchical adaptive controller that likely obsoletes static evolutionary schedules (like in OpenEvolve/FunSearch). The 'Meta-Guidance' mechanism effectively automates the 'researcher-in-the-loop' intervention we manually perform during stagnation, directly addressing our scalability goals.","relevance":{"methodological":9,"problem":9,"inspirational":9},"brief":"AdaEvolve replaces static evolutionary schedules with a three-tier adaptive controller: local exploration intensity based on an 'accumulated improvement signal' (pseudo-gradient), global compute allocation via a normalized bandit, and meta-level 'tactic' generation when stagnation occurs. Results are highly convincing, showing SOTA on Circle Packing (beating AlphaEvolve) and 185 other tasks while using the same LLM backbone as baselines, proving the gains are algorithmic. The most stealable insight is the $G_t$ signal metric—an exponential moving average of squared normalized improvements—which allows auto-tuning exploration rates without manual intervention. This is a direct upgrade for our AlgoEvo architecture, specifically addressing our sample efficiency and stagnation bottlenecks.","specific_domain":"","methods":["llm_evolutionary_search","llm_as_heuristic","adaptive_optimization","multi_armed_bandit","evolutionary_algorithm","island_model_ea","program_synthesis","llm_prompt_optimization"],"problems":["algorithm_discovery","program_generation","combinatorial_optimization","circle_packing","heilbronn_problem","minmax_distance"],"problem_short":"LLM-driven Program Synthesis","benchmarks":["Circle Packing (Square)","Circle Packing (Rectangle)","Heilbronn Problem (Triangle)","Heilbronn Problem (Convex Region)","MinMax Distance","Signal Processing","Telemetry Repair","Cloudcast","Expert Parallelism Load Balancer (EPLB)","Model Placement (Prism)","LLM-SQL","Transaction Scheduling (TXN)","Datacenter TCP Congestion Control (NS3)","Frontier-CS","ARC-AGI-2"],"baselines":["OpenEvolve","GEPA","ShinkaEvolve","AlphaEvolve","Human/SOTA","GPT-5 (single call)"],"vs_baselines":{"AlphaEvolve":"Matches or exceeds on 4/6 mathematical optimization tasks (e.g., 2.636 vs 2.635 on Circle Packing Square), slightly lower on others.","OpenEvolve":"Outperforms on all 6 mathematical optimization tasks (e.g., 2.636 vs 2.541 on Circle Packing Square), all 7 ADRS tasks (e.g., 640.5 vs 729.8 on Cloudcast), Frontier-CS (61.33 vs 50.75 mean score), and ARC-AGI-2 (49% vs 42% accuracy).","GEPA":"Outperforms on all 6 mathematical optimization tasks (e.g., 2.636 vs 2.628 on Circle Packing Square), all 7 ADRS tasks (e.g., 640.5 vs 645.7 on Cloudcast), and Frontier-CS (61.33 vs 43.04 mean score).","ShinkaEvolve":"Outperforms on all 6 mathematical optimization tasks (e.g., 2.636 vs 2.541 on Circle Packing Square), all 7 ADRS tasks (e.g., 640.5 vs 812.7 on Cloudcast), and Frontier-CS (61.33 vs 47.79 mean score).","Human/SOTA":"Matches or exceeds on 4/6 mathematical optimization tasks (e.g., 2.636 vs 2.634 on Circle Packing Square), achieves human-competitive or superior performance in 6/7 ADRS tasks.","GPT-5 (single call)":"Outperforms on Frontier-CS (61.33 vs 20.64 mean score, 3x improvement)."},"novelty_type":"combinatorial_novelty","closest_prior":"OpenEvolve","framework_lineage":"openevolve","llm_model":"GPT-5","code_url":"https://github.com/skydiscover-ai/skydiscover.git","new_benchmark":false,"confidence_results":"hi"},{"id":"2602.13769","title":"OR-Agent: Bridging Evolutionary Search and Structured Research for Automated Algorithm Discovery","authors":["Qi"],"affiliations":"Tongji University","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2026-02-14","priority":8.56,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly challenges the standard population-based evolutionary approach (FunSearch/ReEvo) we use in AlgoEvo, proposing a 'deep research' tree structure that outperforms them significantly. It introduces a concrete mechanism for 'observability'—allowing the agent to write callbacks to probe the environment—which directly addresses our 'better signal for search' priority.","relevance":{"methodological":9,"problem":9,"inspirational":8},"brief":"OR-Agent replaces flat evolutionary loops with a tree-structured research workflow that prioritizes deep iterative refinement and debugging over broad population sampling. The results are compelling, showing a ~2x improvement in normalized scores over ReEvo and FunSearch across 12 OR benchmarks (TSP, CVRP, etc.). The single most actionable takeaway is the **Experiment Agent's environment probing**: instead of relying on scalar fitness, the agent writes custom callbacks to log intermediate states (e.g., 'lane change attempts' in SUMO), enabling genuine diagnosis of failure modes. We should immediately implement this 'instrumentation-via-code' pattern in our own evaluation pipelines to improve signal quality.","specific_domain":"","methods":["multi_agent_system","evolutionary_search","llm_as_heuristic","llm_code_generation","llm_as_evaluator","llm_in_the_loop","llm_evolutionary_search","llm_research_agent"],"problems":["heuristic_evolution","operator_discovery","combinatorial_optimization","tsp","cvrp","bin_packing"],"problem_short":"OR-Agent","benchmarks":["TSP-Constructive","TSP-ACO","TSP-POMO","TSP-LEHD","CVRP-ACO","CVRP-POMO","CVRP-LEHD","BPP-Online","BPP-Offline-ACO","DPP-GA","MKP-ACO","OP-ACO","Cooperative Driving (SUMO)"],"baselines":["FunSearch","AEL","EoH","ReEvo","SUMO default driving model"],"vs_baselines":{"FunSearch":"OR-Agent avg 0.924 vs 0.323","AEL":"OR-Agent avg 0.924 vs 0.477","EoH":"OR-Agent avg 0.924 vs 0.582","ReEvo":"OR-Agent avg 0.924 vs 0.492","SUMO Default":"OR-Agent 90.24 vs 85.25 on driving"},"novelty_type":"combinatorial_novelty","closest_prior":"arXiv:2410.13213","framework_lineage":"funsearch","llm_model":"Qwen3, DeepSeek V3.2","code_url":"https://github.com/qiliuchn/OR-Agent","new_benchmark":false,"confidence_results":"hi"},{"id":"2601.22896","title":"Game-Theoretic Co-Evolution for LLM-Based Heuristic Discovery","authors":["Xinyi"],"affiliations":"Tsinghua University, Chinese Academy of Sciences, University of Chinese Academy of Sciences, AiRiA","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-02-09","priority":8.56,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper effectively renders static-dataset evolutionary search (like standard EoH/FunSearch) obsolete for general-purpose solver discovery. It provides a concrete recipe for implementing adversarial co-evolution in our AlgoEvo framework, directly merging our interests in LLM evolution and multi-agent optimization.","relevance":{"methodological":9,"problem":9,"inspirational":9},"brief":"ASRO adapts Policy Space Response Oracles (PSRO) to code generation, treating heuristic discovery as a zero-sum game where a 'Solver' evolves to minimize gaps and a 'Generator' evolves to create adversarial instances. The results are compelling: it consistently beats the static EoH baseline on TSPLIB and CVRPLIB, proving that adversarial training yields better generalization than training on fixed distributions. The critical takeaway is the architecture: explicitly co-evolving an 'Instance Generator' program alongside the solver prevents overfitting and exposes edge cases (like specific geometric traps in TSP) that static benchmarks miss. This is a direct upgrade to our AlgoEvo/AlphaEvolve pipelines, though it incurs higher computational costs due to the evaluation matrix required for the meta-game.","specific_domain":"","methods":["game_theory","zero_sum_game","policy_space_response_oracles","algorithm_space_response_oracles","llm_code_generation","llm_evolutionary_search","evolution_of_heuristics","program_synthesis"],"problems":["automated_heuristic_discovery","combinatorial_optimization","online_bin_packing","traveling_salesman_problem","capacitated_vehicle_routing_problem"],"problem_short":"CO (OBP, TSP, CVRP)","benchmarks":["Falkenauer T","Falkenauer U","Hard28","Weibull distributions","TSPLIB","CVRPLIB"],"baselines":["First Fit","Best Fit","Nearest Insertion","Farthest Insertion","NN+2-opt","Parallel Insertion","EoH"],"vs_baselines":{"EoH":"Outperforms EoH by 0.5-5% on OBP, 0.5-3% on TSP, and 2-30% on CVRP benchmarks, with larger improvements on harder and larger instances.","First Fit":"Outperforms First Fit by 1-27% on OBP benchmarks.","Best Fit":"Outperforms Best Fit by 0.5-27% on OBP benchmarks.","Nearest Insertion":"Outperforms Nearest Insertion by 19-21% on TSP benchmarks.","Farthest Insertion":"Outperforms Farthest Insertion by 7-12% on TSP benchmarks.","NN+2-opt":"Outperforms NN+2-opt by 18-25% on CVRP benchmarks.","Parallel Insertion":"Outperforms Parallel Insertion by 22-72% on CVRP benchmarks."},"novelty_type":"combinatorial_novelty","closest_prior":"Liu et al., 2024a","framework_lineage":"eoh","llm_model":"DeepSeek-V3.2","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2509.22558","title":"StepORLM: A Self-Evolving Framework With Generative Process Supervision For Operations Research Language Models","authors":["Chenyu"],"affiliations":"Shanghai Jiao Tong University","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-09-26","priority":8.46,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly attacks the limitations of discriminative Process Reward Models (PRMs) which we currently use. The proposed Generative PRM (GenPRM) and Weighted DPO (W-DPO) offer a concrete architectural upgrade for our AlgoEvo and MASPRM projects to handle long-horizon dependencies.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"Zhou et al. propose StepORLM, a framework where an 8B policy and a **Generative Process Reward Model (GenPRM)** co-evolve. Unlike standard discriminative PRMs that score steps in isolation, their GenPRM generates a reasoning trace to evaluate the full trajectory's logic before assigning credit, addressing the interdependency of OR constraints. They align the policy using **Weighted DPO**, where preference weights are derived from the GenPRM's process scores. They claim to beat GPT-4o and DeepSeek-V3 on 6 OR benchmarks (e.g., NL4Opt, MAMO) with an 8B model. **Key Takeaway:** We should test **Generative PRMs** immediately for AlgoEvo; asking the critic to 'explain then score' (generative) rather than just 'score' (discriminative) likely fixes the credit assignment noise in our long-horizon search.","specific_domain":"combinatorial_optimization","methods":["llm_as_heuristic","llm_as_evaluator","llm_code_generation","llm_in_the_loop","llm_evolutionary_search","reinforcement_learning","weighted_direct_preference_optimization","supervised_fine_tuning"],"problems":["operations_research_modeling","linear_programming","mixed_integer_linear_programming","traveling_salesman_problem","combinatorial_optimization"],"problem_short":"OR Modeling","benchmarks":["NL4Opt","MAMO EasyLP","MAMO ComplexLP","NLP4LP","ComplexOR","IndustryOR","ReSocratic"],"baselines":["GPT-4o","DeepSeek-V3","Qwen3-32B","Qwen2.5-72B-Instruct","ORLM","LLMOPT","OptMATH","OptiMUS-v0.3","CoT","CoE","CAFA"],"vs_baselines":{"GPT-4o":"+29.6% Pass@1 accuracy","DeepSeek-V3":"+10.2% Pass@1 accuracy","Qwen3-32B":"+13.1% Pass@1 accuracy","Qwen2.5-72B-Instruct":"+14.9% Pass@1 accuracy","ORLM":"+20.6% Pass@1 accuracy","LLMOPT":"+49.8% Pass@1 accuracy","OptiMUS-v0.3":"+18.5% Pass@1 accuracy","CoT":"+35.3% Pass@1 accuracy","CoE":"+20.1% Pass@1 accuracy","CAFA":"+34.0% Pass@1 accuracy"},"novelty_type":"paradigm_shift","closest_prior":"Process Reward Models (PRMs)","framework_lineage":"steporlm","llm_model":"Qwen3-8B","code_url":"https://github.com/0xzhouchenyu/StepORLM","new_benchmark":false,"confidence_results":"hi"},{"id":"2505.11792","title":"Solver-Informed RL: Grounding Large Language Models for Authentic Optimization Modeling","authors":["Yitian"],"affiliations":"Stanford University, Shanghai Jiao Tong University, The University of Hong Kong, Shanghai University of Finance and Economics, Cardinal Operations","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-05-17","priority":8.46,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"The 'Partial KL' technique (relaxing KL constraints on reasoning traces while enforcing them on code) is a directly transferable innovation for our RL-infused evolutionary search. Additionally, using .lp file structural analysis for reward signals and self-consistency offers a concrete way to improve our process reward models for OR tasks.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"Chen et al. introduce SIRL, a framework for training LLMs to generate optimization models using Reinforcement Learning with Verifiable Rewards (RLVR) and a novel 'Partial KL' surrogate objective. By removing the KL penalty from the reasoning (CoT) section while retaining it for the code generation section, they balance exploration with syntactic stability, achieving SOTA on OptMATH and IndustryOR against OpenAI-o3 and DeepSeek-R1. The critical takeaway for us is the Partial KL strategy: it allows the model to 'think' freely outside the reference distribution while adhering to strict coding standards—a technique we should immediately test in AlgoEvo. Furthermore, their method of parsing .lp files to extract structural features (variable counts, constraint types) for 'instance-enhanced self-consistency' provides a much richer signal than our current binary success/failure metrics.","specific_domain":"automated_optimization_modeling","methods":["reinforcement_learning","reinforce_plus_plus","llm_code_generation","llm_in_the_loop","llm_as_evaluator","data_synthesis","self_consistency","milp_solver"],"problems":["automated_optimization_modeling","milp_general","lp_general","ip_general","nlp_general","socp_general"],"problem_short":"OptModelGen","benchmarks":["NL4OPT","MAMO Easy","MAMO Complex","IndustryOR","OptMATH"],"baselines":["GPT-4","DeepSeek-V3.1","DeepSeek-R1","OpenAI-o3","OptiMUS","ORLM-LLaMA-3-8B","LLMOpt-Qwen2.5-14B","OptMATH-Qwen2.5-7B","OptMATH-Qwen2.5-32B"],"vs_baselines":{"DeepSeek-V3.1":"SIRL-32B achieved +3.3% Macro AVG (68.3% vs 65.0%)","DeepSeek-R1":"SIRL-32B achieved +3.7% Macro AVG (68.3% vs 64.6%)","OpenAI-o3":"SIRL-32B achieved +11.2% Macro AVG (68.3% vs 57.1%)","OptiMUS":"SIRL-7B achieved +11.2% Macro AVG (60.6% vs 49.4%)","ORLM-LLaMA-3-8B":"SIRL-7B achieved +14.2% Macro AVG (60.6% vs 46.4%)","LLMOpt-Qwen2.5-14B":"SIRL-7B achieved +9.5% Macro AVG (60.6% vs 51.1%)","OptMATH-Qwen2.5-7B":"SIRL-7B achieved +5.2% Macro AVG (60.6% vs 55.4%)","OptMATH-Qwen2.5-32B":"SIRL-32B achieved +7.2% Macro AVG (68.3% vs 61.1%)","GPT-4":"SIRL-32B achieved +13.3% Macro AVG (68.3% vs 55.0%)"},"novelty_type":"combinatorial_novelty","closest_prior":"ORLM [25]","framework_lineage":"sirl","llm_model":"Qwen2.5-7B-Instruct, Qwen2.5-32B-Instruct","code_url":"https://github.com/Cardinal-Operations/SIRL","new_benchmark":false,"confidence_results":"hi"},{"id":"2604.16804","title":"AutoOR: Scalably Post-training LLMs to Autoformalize Operations Research Problems","authors":["S."],"affiliations":"X, University of Oxford","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2026-04-18","priority":8.44,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"The paper introduces a highly scalable backtranslation method for generating verified OR training data and uses GRPO with solver-in-the-loop rewards, directly advancing the researcher's focus on OR benchmarking and RL-infused search. The curriculum RL strategy for overcoming cold-start in non-linear problems is a concrete technique the team should adopt.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"AutoOR trains an 8B LLM to autoformalize linear, mixed-integer, and non-linear optimization problems using a scalable backtranslation data generation pipeline and GRPO with solver-execution rewards. The results are strongly backed by empirical evidence, showing the 8B model outperforming Gemini 2.5 Pro and matching Gemini 3 Pro across 9 benchmarks, including a leap from near 0% to 48.98% on a hard non-linear pump network task. The key insight is the backtranslation pipeline: by instantiating standard OR forms to guarantee ground-truth code and then generating natural language descriptions, the authors bypass the hard problem of verifying code generated from ambiguous text. Furthermore, their curriculum RL strategy—temporarily providing solver syntax as privileged information—successfully breaks the cold-start barrier in hard non-linear domains. This is a must-read for work in OR benchmarking and LLM reasoning evaluation, as the data generation and solver-in-the-loop RL techniques directly address the scalability and verification bottlenecks in symbolic OR modeling.","specific_domain":"operations_research_autoformalization","methods":["RL_GRPO","synthetic_data_generation","curriculum_learning","backtranslation"],"problems":["linear_programming","mixed_integer_programming","non_linear_programming"],"problem_short":"OR Autoformalization","benchmarks":["NL4Opt","NL4LP","MAMO-Easy","MAMO-Complex","IndustryOR","ComplexOR","Hard-LP","Hard-MIP","Pump-NLP"],"baselines":["Qwen3-8B instruct","Gemini 2.5 Pro","Gemini 3 Pro","ORLM (8B)","Step-Opt (8B)","OptMATH (32B)","OR-R1SFT (8B)","OR-R1RL (8B)"],"vs_baselines":{"Qwen3-8B instruct":"AutoOR +13-49% across all","Gemini 2.5 Pro":"AutoOR +4-16% (most), -5.55% (IndustryOR)","Gemini 3 Pro":"AutoOR competitive, e.g., +4% (MAMO-Easy), -7.14% (IndustryOR)","ORLM (8B)":"AutoOR +3.6-26.15% on tested","Step-Opt (8B)":"AutoOR +8.7-32.65% (most), -5.93% (NL4OPT)","OptMATH (32B)":"AutoOR +4.1-28.9% (most), -17.33% (NL4OPT)","OR-R1SFT (8B)":"AutoOR +7-43.1% on tested","OR-R1RL (8B)":"AutoOR +7.9-33.1% on tested","Frontier Models (Pump-NLP)":"AutoOR 48.98% vs near 0%"},"novelty_type":"combinatorial_novelty","closest_prior":"Operations Research, 73(6):2986–3009, November 2025","framework_lineage":"autoor","llm_model":"Qwen3-8B","code_url":null,"new_benchmark":true,"confidence_results":"hi"},{"id":"2509.19349","title":"ShinkaEvolve: Towards Open-Ended And Sample-Efficient Program Evolution","authors":["Robert"],"affiliations":"Sakana AI","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-09-17","priority":8.41,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly attacks the sample efficiency bottleneck of AlphaEvolve-style search, achieving SOTA results with 150 samples where we typically spend thousands. It provides concrete, low-hanging engineering fixes (embedding rejection, bandit selection) that we should immediately port to AlgoEvo.","relevance":{"methodological":9,"problem":9,"inspirational":8},"brief":"ShinkaEvolve presents an open-source evolutionary framework that drastically improves sample efficiency (e.g., beating AlphaEvolve on Circle Packing with only 150 evaluations vs. thousands) by integrating embedding-based novelty rejection, adaptive parent sampling, and bandit-based LLM selection. The results are credible, backed by code from Sakana AI, and directly target our primary pain point of high API costs/sample inefficiency in evolutionary search. **Key Takeaway:** We must implement their 'novelty rejection sampling' immediately—using a cheap embedding model to filter out semantically similar code mutations (threshold 0.95) before execution is a trivial but high-impact optimization for our AlgoEvo pipeline. This paper proves that smart filtering is superior to the brute-force compute strategies we have been relying on.","specific_domain":"","methods":["evolutionary_algorithms","llm_as_mutation_operator","llm_as_evaluator","llm_code_generation","llm_evolutionary_search","program_synthesis","evolution_of_heuristics","simulated_annealing"],"problems":["circle_packing","mathematical_reasoning","agent_design","competitive_programming","heuristic_evolution","load_balancing"],"problem_short":"Program Evolution","benchmarks":["Circle Packing","AIME 2024","ALE-Bench LITE","Mixture-of-Expert Load Balancing Loss"],"baselines":["AlphaEvolve","OpenEvolve","LLM4AD","ALE-Agent","global-batch LBL","simple single-query agents","majority-voting approaches"],"vs_baselines":{"AlphaEvolve":"new SOTA on circle packing with <150 samples","AIME baselines":"significantly outperforms hand-designed agents","ALE-Agent":"+2.3% average improvement, 5th to 2nd on ahc039","global-batch LBL":"consistent edge in perplexity and task performance"},"novelty_type":"incremental","closest_prior":"AlphaEvolve","framework_lineage":"alphaevolve","llm_model":"gemini-2.5-pro, claude-sonnet-4, o4-mini, gpt-4.1-nano, gpt-4.1, gpt-4.1-mini, gemini-2.5-flash, gpt-5, gpt-5-mini","code_url":"https://github.com/SakanaAI/ShinkaEvolve","new_benchmark":false,"confidence_results":"lo"},{"id":"2602.21515","title":"Training Generalizable Collaborative Agents via Strategic Risk Aversion","authors":["Chengrui"],"affiliations":"Caltech","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2026-02-25","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper provides a rigorous algorithmic solution (SRPO) to the 'lazy agent' / free-riding problem in multi-agent systems, which is a critical bottleneck in our multi-agent debate (HERMES) and robust optimization (RobustMAS) work. The application to LLM debate on GSM8K demonstrates immediate transferability to our text-based domains, offering a mathematical fix to a problem we usually try to solve with prompting.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Qu et al. introduce Strategically Risk-Averse Policy Optimization (SRPO), which trains agents against a 'constrained adversary' that minimizes their reward within a KL-divergence bound of the partner's current policy. Theoretical results prove this objective eliminates free-riding equilibria, and experiments on GSM8K multi-agent debate show it prevents 'lazy' agreement, improving joint accuracy by up to 19% when pairing heterogeneous LLMs (e.g., 0.6B with 4B). The key takeaway is that robustness to partner deviation—enforced via this specific adversarial objective—is a more principled way to fix lazy agent behavior than prompt engineering or simple dropout. We should immediately test this objective in our HERMES debate framework to improve the contribution quality of smaller models.","specific_domain":"multi_agent_coordination","methods":["strategic_risk_aversion","risk_averse_quantal_response_equilibria","policy_optimization","independent_proximal_policy_optimization","ppo","adversarial_training","entropy_regularization","multi_agent_reinforcement_learning"],"problems":["partner_generalization","multi_agent_coordination","free_riding_mitigation","overcooked","tag","hanabi"],"problem_short":"Partner Generalization","benchmarks":["Overcooked Gridworld (modified)","Tag (PettingZoo MPE simple_tag_v3)","Hanabi (3 colors, 3 ranks)","GSM8K (LLM-based multi-agent debate)"],"baselines":["Independent Proximal Policy Optimization (IPPO)"],"vs_baselines":{"IPPO (Overcooked)":"SRPO achieves higher utility and improved cross-play reliability, IPPO finds free-riding equilibria","IPPO (Tag)":"SRPO shows slightly lower training performance but significantly better generalization against unseen runners and partners","IPPO (Hanabi)":"SRPO is more robust; IPPO performance drops -24.8% from training to cross-play, SRPO drops -15.8%","IPPO (LLM Debate)":"SRPO improves joint accuracy by up to 19.27% and individual accuracy by up to 14.49%"},"novelty_type":"combinatorial_novelty","closest_prior":"Mazumdar et al. (2024)","framework_lineage":"srpo","llm_model":"Qwen2.5-0.5B-Instruct, Qwen2.5-3B-Instruct, Qwen3-0.6B, Qwen3-4B-Instruct-2507, Llama 3.2-1B-Instruct","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2602.07663","title":"A Two-Layer Framework for Joint Online Configuration Selection and Admission Control","authors":["Owen"],"affiliations":"Massachusetts Institute of Technology, Stanford University","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2026-02-07","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper provides a rigorous mathematical proof that static configuration selection (e.g., picking one 'best' quantization level) is suboptimal for multi-resource LLM serving. It offers a concrete primal-dual algorithm to learn optimal configuration mixtures, which is directly applicable to our 'GPUSched' and 'OR formulations for LLM serving' projects.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"The authors introduce a 'switching-aware' primal-dual framework for joint configuration selection (e.g., quantization, parallelism) and admission control, demonstrating that dynamically mixing configurations allows for higher resource utilization than any single fixed configuration. Results are rigorous, backed by $\\tilde{O}(\\sqrt{T})$ regret bounds and experiments on Alibaba cluster traces where the method achieves ~97% competitive ratio (vs. ~85% for greedy). The key takeaway is the 'switching-aware fluid oracle' concept: our resource allocation models for LLM serving must optimize over the convex hull of configurations (mixing CPU-heavy and Mem-heavy setups) rather than searching for a single static optimum. We should adapt their saddle-point formulation for the GPUSched project to handle heterogeneous resource constraints more effectively.","specific_domain":"","methods":["online_optimization","bandits_with_knapsacks","online_linear_programming","saddle_point_optimization","ucb","threshold_rules","linear_programming","primal_dual_methods"],"problems":["resource_allocation","admission_control","configuration_selection","llm_serving_optimization","gpu_scheduling","revenue_management"],"problem_short":"OCSAC","benchmarks":["Gaussian scenario (S0)","Alibaba Cluster Trace v2018","Complementarity scenario (S4)"],"baselines":["Greedy (α=0)","Random","Oracle","OneHot"],"vs_baselines":{"Greedy":"SP-UCB-OLP (α=0.01) achieves 97.38% CR on Alibaba (vs. Greedy 84.81% CR). On S4, SP-UCB-OLP achieves 0.91 CRmix (vs. Greedy 0.96 CRmix).","Random":"SP-UCB-OLP (α=0.01) achieves 97.38% CR on Alibaba (vs. Random 61.05% CR). On S4, SP-UCB-OLP achieves 0.91 CRmix (vs. Random 0.99 CRmix).","Oracle":"SP-UCB-OLP (α=0.01) achieves 97.38% CR on Alibaba, approaching Oracle performance (99.95% CR).","OneHot":"On S4, OneHot achieves 0.51 CRmix, significantly lower than SP-UCB-OLP (0.91 CRmix), confirming its inability to exploit complementarity."},"novelty_type":"combinatorial_novelty","closest_prior":"Online linear programming (Agrawal et al., 2014)","framework_lineage":"","llm_model":"","code_url":"https://github.com/owenshens/A-Two-Layer-Framework-for-Joint-Online-Configuration-Selection-and-Admission-Control","new_benchmark":false,"confidence_results":"lo"},{"id":"2502.07115","title":"Online Scheduling for LLM Inference with KV Cache Constraints","authors":["Patrick"],"affiliations":"Massachusetts Institute of Technology, Microsoft Research, HKUST","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2026-01-15","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper provides the exact mathematical foundation (IP formulation + hardness proofs) for our active 'GPUSched' project. It demonstrates why standard scheduling fails due to dynamic KV-cache growth and offers a proven heuristic (MC-SF) that we should immediately implement as a baseline.","relevance":{"methodological":8,"problem":10,"inspirational":8},"brief":"This paper formulates LLM inference scheduling as an Integer Program (IP) that explicitly models the linear memory growth of KV caches, and proposes a 'Memory Constrained Shortest First' (MC-SF) algorithm. The results are rigorous, showing MC-SF achieves near-optimal performance (within 5% of hindsight optimal) on synthetic data and significantly outperforms standard FCFS/threshold heuristics on real traces. The critical takeaway is the 'future feasibility check' (Eq. 5), which validates that a batch will *remain* within memory limits throughout the generation process based on predicted output lengths—a necessary deviation from standard static-size scheduling. This is foundational reading for our GPUSched project, providing both the exact IP baseline we need and a strong heuristic to benchmark against.","specific_domain":"llm_inference_scheduling","methods":["online_optimization","scheduling","batching","integer_programming","competitive_ratio_analysis","shortest_first","memory_constrained_scheduling","online_algorithms"],"problems":["llm_inference_scheduling","resource_allocation","kv_cache_management","online_scheduling"],"problem_short":"LLM Inference Scheduling","benchmarks":["Synthetic datasets","LMSYS-Chat-1M (Zheng et al., 2023)"],"baselines":["Hindsight Optimal","α-protection greedy algorithms","α-protection, β-clearing algorithms","Memory Constrained Benchmark (MC-Benchmark)","FCFS"],"vs_baselines":{"Hindsight Optimal (All-at-once)":"1.005x average latency, 1.074x worst-case","Hindsight Optimal (Online stochastic)":"1.047x average latency, 1.227x worst-case","MC-Benchmark (High Demand)":"3x lower latency growth rate","MC-Benchmark (Low Demand)":"8x lower latency growth rate","Benchmark α=0.3 (1000 requests, λ=50)":"+61.7% latency","Benchmark α=0.25 (1000 requests, λ=50)":"+58.9% latency","Benchmark α=0.2, β=0.2 (1000 requests, λ=50)":"+57.0% latency","Benchmark α=0.2, β=0.1 (1000 requests, λ=50)":"+57.0% latency","Benchmark α=0.1, β=0.2 (1000 requests, λ=50)":"+66.2% latency","Benchmark α=0.1, β=0.1 (1000 requests, λ=50)":"+58.4% latency","FCFS (with ϵ=0.8 prediction error)":"Significantly lower latency"},"novelty_type":"new_problem","closest_prior":"Bari et al., 2025","framework_lineage":"","llm_model":"","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2504.11320","title":"Optimizing LLM Inference: Fluid-Guided Online Scheduling with Memory Constraints","authors":["Ruicheng"],"affiliations":"Massachusetts Institute of Technology, Peking University, Alibaba Group","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2026-01-05","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper is a direct hit for our 'GPUSched' project. It provides a rigorous Operations Research formulation (fluid dynamics + queueing theory) for LLM inference that solves the unknown output length problem without requiring predictive ML models, offering a theoretical guarantee against memory eviction.","relevance":{"methodological":8,"problem":10,"inspirational":8},"brief":"This paper formulates LLM inference as a multi-stage stochastic scheduling problem, introducing 'Nested WAIT'—a threshold-based algorithm that handles unknown output lengths by letting prompts classify themselves as they survive into deeper decode segments. Unlike heuristic baselines (vLLM, Sarathi), they provide rigorous asymptotic optimality proofs and high-probability bounds against memory overflow, validated on A100 simulations. The key takeaway is the 'nested segment' mechanism: instead of predicting job size, structure the queue so short jobs exit early and long jobs naturally migrate to lower-priority/protected tiers, effectively decoupling the memory risk. We should immediately evaluate this threshold logic for our GPUSched formulations, as it likely outperforms our current predictive or FCFS approaches for handling KV cache growth.","specific_domain":"llm_inference_scheduling","methods":["fluid_dynamics_approximation","online_scheduling","threshold_based_scheduling","queueing_theory","asymptotic_analysis","martingale_theory","doobs_inequality","union_bound"],"problems":["llm_inference_scheduling","memory_constrained_scheduling","online_scheduling","llm_serving_optimization","resource_allocation"],"problem_short":"LLM inference scheduling","benchmarks":["vLLM","Sarathi"],"baselines":["vLLM (Kwon et al. 2023)","Sarathi (Agrawal et al. 2023)"],"vs_baselines":{"vLLM":"Superior throughput and reduced latency across synthetic and real-world datasets.","Sarathi":"Superior throughput and reduced latency across synthetic and real-world datasets."},"novelty_type":"combinatorial_novelty","closest_prior":"Jaillet et al. (2025)","framework_lineage":"","llm_model":"","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2512.18134","title":"Optimal Software Pipelining and Warp Specialization for Tensor Core GPUs","authors":["Rupanshu"],"affiliations":"Stanford University, NVIDIA","category":"OR for Generative AI","subdomain":"gpu_scheduling","date":"2025-12-19","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper successfully applies formal OR methods (ILP/SMT) to solve low-level GPU instruction scheduling and warp specialization, a domain typically dominated by heuristics or manual tuning. It directly addresses your interest in 'OR formulations for AI systems' and provides a rigorous alternative (or complement) to evolutionary code search for kernel optimization.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Twill formulates the complex interplay of software pipelining and warp specialization on modern GPUs (Hopper/Blackwell) as a joint SMT/ILP optimization problem, automatically rediscovering expert-tuned Flash Attention schedules without heuristics. The results are rigorous, matching hand-tuned performance within 1-2% and handling new hardware constraints (Blackwell TMEM) automatically. The key takeaway is the 'cost normalization' technique via ILP to make the scheduling search space tractable, and the demonstration that exact constraint solvers can replace human intuition for complex kernel generation. This is essential reading for your work on OR formulations for GPU scheduling and LLM serving optimization, offering a deterministic baseline to compare against evolutionary approaches.","specific_domain":"tensor_core_scheduling","methods":["software_pipelining","warp_specialization","modulo_scheduling","integer_linear_programming","satisfiability_modulo_theories","constraint_satisfaction_problem","compiler_optimization","code_generation"],"problems":["gpu_scheduling","tensor_core_scheduling","flash_attention","matrix_multiplication_optimization"],"problem_short":"SWP and WS for TC GPUs","benchmarks":["Flash Attention Forward Pass","Flash Attention Backward Pass"],"baselines":["Triton","Triton-Tiled","CUDA-Default","cuDNN","Flash Attention 3 (FA3)","Flash Attention 4 (FA4)","Twill-SWP","Twill-SWP-Triton-WS","CUDA-Triton-WS","Twill-LR"],"vs_baselines":{"Flash Attention Forward Pass (Hopper)":"within 1% of official FA3 implementation; significantly outperformed Triton, Triton-Tiled, CUDA-Default","Flash Attention Forward Pass (Blackwell)":"within 2% of FA4; competitive with cuDNN; significantly better than Triton, Triton-Tiled, CUDA-Default; Twill-SWP-Triton-WS and CUDA-Triton-WS yielded no benefit","Flash Attention Backward Pass (Hopper)":"11% worse than FA3 (due to tile size); competitive with cuDNN on highest sequence length","Flash Attention Backward Pass (Blackwell)":"Twill-LR yielded small speedup over default implementation, competitive with FA4 and cuDNN"},"novelty_type":"combinatorial_novelty","closest_prior":"PipeThreader","framework_lineage":"twill","llm_model":"","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2406.01566","title":"Helix: Serving Large Language Models over Heterogeneous GPUs and Network via Max-Flow","authors":["Yixuan"],"affiliations":"Carnegie Mellon University","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2025-03-05","priority":8.36,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper is a definitive reference for our 'GPUSched' and 'OR formulations for AI systems' active projects. It successfully demonstrates that rigorous OR formulations (Max-Flow/MILP) significantly outperform standard systems heuristics for LLM serving, validating our research thesis.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Helix formulates distributed LLM serving on heterogeneous clusters as a max-flow problem, using MILP to optimize model placement and deriving a per-request weighted round-robin scheduler from the flow solution. Unlike standard static pipeline parallelism, it routes every request dynamically based on edge capacities, achieving up to 3.3x throughput gains over Swarm on mixed GPU clusters (L4/T4/A100). The results are rigorous, backed by both physical cluster experiments and high-fidelity simulations. The critical takeaway is the 'per-request pipeline' abstraction: decoupling request routing from static device assignment allows exact OR methods to maximize utilization of weaker hardware—a technique we should immediately evaluate for our GPUSched project.","specific_domain":"llm_serving_optimization","methods":["max_flow_optimization","milp","pipeline_parallelism","tensor_parallelism","scheduling_algorithms","weighted_round_robin","kv_cache_management","dynamic_batching"],"problems":["llm_serving_optimization","model_placement","resource_scheduling"],"problem_short":"Heterogeneous LLM Serving","benchmarks":["Azure Conversation dataset"],"baselines":["Swarm [45]","separate pipelines (SP)","Petals [5]","random scheduling","Shortest Queue First scheduling (SQ)"],"vs_baselines":{"Swarm":"up to 3.3x decode throughput (online, high-heterogeneity cluster, LLaMA 70B), up to 66% prompt latency reduction (online, geo-distributed, LLaMA 30B)","separate pipelines (SP)":"up to 3.29x decode throughput (online, high-heterogeneity cluster, LLaMA 70B)","Petals":"up to 1.49x decode throughput (offline, geo-distributed, LLaMA 70B)","random scheduling":"up to 29% decode throughput (offline, single cluster, LLaMA 70B)","Shortest Queue First scheduling (SQ)":"up to 19% decode throughput (offline, geo-distributed, LLaMA 70B)"},"novelty_type":"combinatorial_novelty","closest_prior":"Petals [5]","framework_lineage":"","llm_model":"","code_url":"https://github.com/Thesys-lab/Helix-ASPLOS25","new_benchmark":false,"confidence_results":"hi"},{"id":"2603.07970","title":"Advancing Automated Algorithm Design via Evolutionary Stagewise Design with LLMs","authors":["Chen"],"affiliations":"Nanjing University, Huawei Noah’s Ark Lab","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-03-09","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly addresses our core bottleneck in LLM evolutionary search—sample efficiency—by replacing black-box end-to-end rewards with stagewise intermediate feedback and a multi-agent reflection mechanism. It beats AlphaEvolve using only 25 evaluations, making it a critical read for the AlgoEvo project.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"EvoStage enhances LLM-based automated algorithm design by decomposing the generation process into sequential stages, using a multi-agent system (coordinator and coders) to iteratively refine code based on real-time intermediate execution feedback. The results are highly credible and backed by strong empirical numbers; it achieves state-of-the-art HPWL on 16 chip placement benchmarks and beats AlphaEvolve/EoH on Bayesian Optimization tasks using an incredibly small budget of just 9 to 25 evaluations. The single most useful takeaway is the shift from black-box end-to-end evaluation to stagewise intermediate feedback, where a coordinator agent reflects on mid-execution metrics to guide the next stage of heuristic design. This matters immensely for our AlgoEvo and MASPRM projects; we should immediately test pausing our VRP/scheduling environments mid-execution to feed intermediate state metrics to a coordinator LLM, which could drastically reduce the number of LLM samples we need to find optimal heuristics.","specific_domain":"","methods":["evolutionary_algorithms","llm_evolutionary_search","llm_code_generation","llm_in_the_loop","multi_agent_system","chain_of_thought","gradient_based_optimization","adam_optimizer"],"problems":["automated_algorithm_design","chip_placement","global_placement","black_box_optimization","hyperparameter_optimization","neural_architecture_search"],"problem_short":"AAD","benchmarks":["ISPD 2005","ICCAD 2015","BoTorch synthetic functions","HPO-NAS problems"],"baselines":["DREAMPlace-Nesterov [20]","Xplace-NN [21]","DREAMPlace-Adam [20]","EoH [4]","AlphaEvolve [3]","UCB [51]","EI [50]","Commercial 3D placer"],"vs_baselines":{"DREAMPlace-Nesterov [20]":"Outperforms on all 16 chip cases (avg HPWL ratio 1.000 vs 1.009/1.019)","Xplace-NN [21]":"Outperforms on all 16 chip cases (avg HPWL ratio 1.000 vs 1.033/1.017)","DREAMPlace-Adam [20]":"EvoStage-single achieves avg HPWL ratio 0.979 (ISPD 2005) and 0.990 (ICCAD 2015) vs 1.000","EoH [4]":"EvoStage-single achieves avg HPWL ratio 0.979 vs 1.227 (ISPD 2005) and 0.990 vs 1.029 (ICCAD 2015), with higher Pass Rates","AlphaEvolve [3]":"EvoStage-single achieves avg HPWL ratio 0.979 vs 1.029 (ISPD 2005) and 0.990 vs 0.998 (ICCAD 2015), with higher Pass Rates","UCB [51]":"Achieves Avg Rank 1 vs 4.25 on Optimal Gap for BO benchmarks","EI [50]":"Achieves Avg Rank 1 vs 3.875 on Optimal Gap for BO benchmarks","Commercial 3D placer":"9.24% HPWL improvement on logic die, 7.51% on memory die, 52.21% optimization iteration improvement"},"novelty_type":"combinatorial_novelty","closest_prior":"AlphaEvolve","framework_lineage":"","llm_model":"gpt-4o","code_url":null,"new_benchmark":false,"confidence_results":"lo"},{"id":"2602.03132","title":"Contrastive Concept-Tree Search for LLM-Assisted Algorithm Discovery","authors":["Timothee"],"affiliations":"","category":"LLMs for Algorithm Design","subdomain":"program_synthesis","date":"2026-02-03","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a structural upgrade to the standard LLM evolutionary loop (AlphaEvolve) by inserting an explicit 'semantic concept' layer. It solves the 'black box' mutation problem by learning which algorithmic strategies (concepts) correlate with performance, directly addressing our goals for sample efficiency, memory, and observability in AlgoEvo.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"The authors introduce Contrastive Concept-Tree Search (CCTS), which modifies the standard evolutionary loop by prompting the LLM to extract semantic 'concepts' from every generated program, building a dynamic hierarchy. They then apply a Tree-structured Parzen Estimator (TPE) to these concepts to learn a contrastive utility model (p(concept|good)/p(concept|bad)), using this to bias parent selection towards promising algorithmic strategies. Results are rigorous, showing consistent improvements over k-elite baselines on combinatorial tasks like Circle Packing, with a synthetic ablation confirming the model learns ground-truth concept utilities. **Key Takeaway:** We should immediately implement the 'Concept TPE' loop in AlgoEvo—asking the LLM to tag generated heuristics with concepts and maintaining a weight vector over these concepts provides a cheap, interpretable 'process reward model' to guide search.","specific_domain":"","methods":["llm_as_heuristic","llm_code_generation","evolution_of_heuristics","program_synthesis","self_improving_search","tree_structured_parzen_estimator","cross_entropy_method","contrastive_learning"],"problems":["algorithm_discovery","heuristic_evolution","combinatorial_optimization","circle_packing_problem","arithmetic_kakeya_conjecture","heilbronns_triangle_problem"],"problem_short":"Algorithm Discovery","benchmarks":["Circle packing problem","Arithmetic Kakeya Conjecture","Heilbronn’s Triangle Problem","Squares-in-Square problem"],"baselines":["Greedy selection","k-elite selection (k=5)","Uniform selection"],"vs_baselines":{"Greedy selection":"CCTS consistently achieves higher scores and faster improvement across all tasks compared to Greedy selection, with a reduced width of the lower tail of the performance distribution.","k-elite selection (k=5)":"CCTS consistently achieves higher scores and faster improvement across all tasks compared to k-elite selection, with a reduced width of the lower tail of the performance distribution.","Uniform selection":"CCTS consistently achieves higher scores and faster improvement across all tasks compared to Uniform selection, with a reduced width of the lower tail of the performance distribution."},"novelty_type":"combinatorial_novelty","closest_prior":"FunSearch","framework_lineage":"","llm_model":"gemini-2.0-flash","code_url":null,"new_benchmark":true,"confidence_results":"hi"},{"id":"2512.13857","title":"EvoLattice: Persistent Internal-Population Evolution through Multi-Alternative Quality-Diversity Graph Representations for LLM-Guided Program Discovery","authors":["Kamer"],"affiliations":"aiXplain Inc","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-12-17","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a representational shift (DAG of alternatives vs. single program) that directly solves the credit assignment problem in LLM-based evolution—a core bottleneck in our AlgoEvo and AlphaEvolve work. It effectively implements a structural Process Reward Model without training a separate value network.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"EvoLattice replaces the standard 'overwrite-based' evolution of monolithic programs with a persistent DAG where each node holds multiple alternative implementations, evaluating all valid combinatorial paths to compute fine-grained performance statistics for every micro-operator. The results are strong: it outperforms AlphaEvolve and FunSearch styles on NAS-Bench-Zero by explicitly preserving diversity and enabling surgical, data-driven pruning rather than blind mutation. The critical takeaway is the 'alternative-level statistic' mechanism: by aggregating performance across all paths a component participates in, they generate a high-fidelity signal that tells the LLM exactly which lines of code are working, effectively solving the sparse reward problem in code evolution. We should immediately discuss refactoring our AlgoEvo representation to support this multi-alternative graph structure, as it maximizes signal extraction per LLM call.","specific_domain":"","methods":["llm_evolutionary_search","program_synthesis","evolution_of_heuristics","quality_diversity","directed_acyclic_graph","memoization","llm_code_generation","llm_in_the_loop"],"problems":["program_synthesis","agent_design","neural_architecture_search_proxy_discovery","optimizer_discovery"],"problem_short":"null","benchmarks":["NAS-Bench-Suite-Zero (Medium)","Training-free optimizer update rule discovery"],"baselines":["Spectral Energy (mean)","Covariance Trace","Spectral + Covariance (fixed)","ZeroLM (Chen et al., 2025)","LPZero (Dong et al., 2024)","FunSearch-style proxy generation","AlphaEvolve-style diff evolution","ShinkaEvolve-like parent sampling","SGD (-g)","SignSGD (Bernstein et al., 2018)","Lion (Chen et al., 2023)","Curvature-normalized (-g/√h)","Sign + curvature (linear blend)","Sign + curvature (nonlinear gating)"],"vs_baselines":{"Spectral Energy (mean)":"+158.3% ρ on NAS-Bench-Suite-Zero","Covariance Trace":"+121.4% ρ on NAS-Bench-Suite-Zero","Spectral + Covariance (fixed)":"+93.75% ρ on NAS-Bench-Suite-Zero","ZeroLM (Chen et al., 2025)":"+72.2% ρ on NAS-Bench-Suite-Zero","LPZero (Dong et al., 2024)":"+55.0% ρ on NAS-Bench-Suite-Zero","FunSearch-style proxy generation":"+72.2% ρ on NAS-Bench-Suite-Zero","AlphaEvolve-style diff evolution":"+40.9% ρ on NAS-Bench-Suite-Zero","ShinkaEvolve-like parent sampling":"+29.1% ρ on NAS-Bench-Suite-Zero","SGD (-g)":"+89.4% score on Optimizer Discovery","SignSGD (Bernstein et al., 2018)":"+50.3% score on Optimizer Discovery","Lion (Chen et al., 2023)":"+44.6% score on Optimizer Discovery","Curvature-normalized (-g/√h)":"+40.8% score on Optimizer Discovery","Sign + curvature (linear blend)":"+31.8% score on Optimizer Discovery","Sign + curvature (nonlinear gating)":"+23.9% score on Optimizer Discovery"},"novelty_type":"paradigm_shift","closest_prior":"FunSearch","framework_lineage":"evolattice","llm_model":"GPT-OSS-20B","code_url":null,"new_benchmark":false,"confidence_results":"lo"},{"id":"2510.08755","title":"Robust Heuristic Algorithm Design with LLMs","authors":["Pantea"],"affiliations":"Microsoft, MIT, Microsoft Research, University of Southern California, The University of Texas at Austin","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-10-09","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper provides a concrete architecture for 'white-box' evolutionary search, replacing FunSearch's blind mutation with solver-guided debugging. It directly addresses our need for better feedback signals in AlgoEvo by integrating formal counter-examples and natural language explanations into the loop.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"Karimi et al. introduce 'Robusta', an enhancement to FunSearch that uses a Heuristic Analyzer (solver-based) to identify adversarial inputs and a Suggester LLM to explain *why* the current heuristic fails before generating new code. They demonstrate a 28x improvement in worst-case performance over FunSearch on traffic engineering tasks, with results backed by rigorous comparison against optimal solvers. The critical takeaway is the 'Suggester' intermediate step: converting raw failure instances into natural language coding strategies significantly improves the LLM's ability to fix logic bugs compared to raw samples alone. We should immediately attempt to replicate this 'Analyzer -> Explainer -> Coder' loop for our VRP work, using small-scale solvers to generate counter-examples for our evolved ALNS operators.","specific_domain":"traffic_engineering","methods":["llm_as_heuristic","llm_code_generation","llm_evolutionary_search","funsearch","evolution_of_heuristics","genetic_algorithm","heuristic_analysis","combinatorial_reasoning"],"problems":["robust_algorithm_design","heuristic_design","traffic_engineering","network_routing"],"problem_short":"RHAD","benchmarks":["Microsoft’s traffic engineering heuristic","CogentCo topology from the Topology Zoo"],"baselines":["FunSearch"],"vs_baselines":{"FunSearch":"Robusta achieves 0.5% max suboptimality vs 14% for FunSearch; 0.01% mean suboptimality vs 2.07% for FunSearch; 1.00x runtime vs 0.96x for FunSearch"},"novelty_type":"combinatorial_novelty","closest_prior":"FunSearch","framework_lineage":"funsearch","llm_model":"Open-AI’s o4-mini","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2410.15639","title":"Can Large Language Models Invent Algorithms to Improve Themselves?: Algorithm Discovery for Recursive Self-Improvement through Reinforcement Learning","authors":["Yoichi"],"affiliations":"NEC Corporation","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-06-10","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper successfully implements 'RL-infused evolution' by using Direct Preference Optimization (DPO) to fine-tune the code generator based on search results. This provides a concrete, proven mechanism to achieve our 'Evolving the Evolver' objective in AlgoEvo, moving beyond static prompting.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"Ishibashi et al. propose 'Self-Developing,' a framework where an LLM generates Python code for model merging, evaluates the results, and uses the performance data to fine-tune the generator via DPO in a recursive loop. The results are empirically strong, outperforming human-designed baselines (Task Arithmetic) by 4.3% on GSM8k and demonstrating that the generator explicitly learns better strategies over iterations. **Key Takeaway:** We can replace the static mutation operators in our evolutionary search with a DPO-trained model that learns from the search history—effectively implementing 'learning to search.' This is a direct, actionable upgrade for our AlgoEvo and AlphaEvolve pipelines.","specific_domain":"mathematical_reasoning","methods":["rl_dpo","llm_code_generation","llm_as_evaluator","llm_fine_tuned","llm_evolutionary_search","program_synthesis","self_improving_search"],"problems":["algorithm_discovery","mathematical_reasoning","model_merging"],"problem_short":"LLM Algorithm Discovery","benchmarks":["GSM8k","MATH"],"baselines":["Task Arithmetic (Ilharco et al., 2023)","TIES Merging (Yadav et al., 2023)","Model Stock (Jang et al., 2024)"],"vs_baselines":{"Task Arithmetic (original)":"+4.2% on GSM8k (76.1% vs 71.9%), comparable on MATH (8.5% vs 8.5%)","TIES Merge (original)":"+4.3% on GSM8k (76.1% vs 71.8%), +0.1% on MATH (8.5% vs 8.4%)","Model Stock (original)":"+36.6% on GSM8k (76.1% vs 39.5%), +2.4% on MATH (8.5% vs 6.1%)","Task Arithmetic (transfer)":"+7.4% on GSM8k (78.8% vs 71.4%), +108% on MATH (2.5% vs 1.2%)"},"novelty_type":"combinatorial_novelty","closest_prior":"FunSearch","framework_lineage":"self_developing","llm_model":"openchat-3.5-1210","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2505.12285","title":"CALM: Co-evolution of Algorithms and Language Model for Automatic Heuristic Design","authors":["Ziyao"],"affiliations":"City University of Hong Kong, Southeast University, University of Victoria, Hon Hai Research Institute","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2025-05-18","priority":8.31,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper successfully implements 'RL-infused evolution'—a key item on our research agenda—by fine-tuning the LLM weights during the search using GRPO. It proves that a small, locally adapted model (7B) can outperform frozen SOTA models (GPT-4o) in heuristic generation, directly challenging our reliance on large, frozen APIs for AlgoEvo.","relevance":{"methodological":9,"problem":8,"inspirational":9},"brief":"CALM introduces a hybrid evolutionary framework that fine-tunes the LLM generator *during* the search process using Group Relative Policy Optimization (GRPO), rather than relying solely on prompt evolution. Using a quantized Qwen-7B model on a single consumer GPU, it outperforms GPT-4o-based baselines (FunSearch, EoH) on Bin Packing and VRP benchmarks. The critical takeaway is their reward function design: instead of absolute performance, they reward the *relative improvement* of the generated code over the specific 'parent' heuristics in the prompt, stabilizing the RL signal. We should immediately test this 'online fine-tuning' approach to reduce our API costs and improve sample efficiency in AlgoEvo.","specific_domain":"","methods":["evolutionary_search","heuristic_evolution","llm_fine_tuned","rl_trained","grpo","llm_evolutionary_search","genetic_algorithm","llm_as_heuristic"],"problems":["bin_packing","tsp","cvrp","orienteering_problem","algorithm_discovery","heuristic_evolution"],"problem_short":"AHD","benchmarks":["Online Bin Packing (OBP)","Traveling Salesman Problem (TSP)","Capacitated Vehicle Routing Problem (CVRP)","Orienteering Problem (OP)"],"baselines":["Best-Fit [38]","First Fit","Greedy-Construct (GC) [39]","ACO [40]","POMO [14]","DeepACO [41]","FunSearch [13]","EoH [8]","ReEvo [9]","HSEvo [10]","MCTS-AHD [11]","EvoTune [33]"],"vs_baselines":{"MCTS-AHD (GPT-4o-mini)":"Outperforms on OBP (-20.2% avg gap), CVRP (-16% to -30% avg gap), OP (-4% to -23% avg gap). Outperforms on TSP N=200 (-2.2% gap).","POMO":"Outperforms on TSP N=200 (-34.4% gap); POMO is superior on TSP N=50/100.","FunSearch (GPT-4o-mini)":"Outperforms on OBP (-28.3% avg gap).","EvoTune (Phi3.5-mini-Instruct)":"Outperforms on OBP (-69.9% avg gap)."},"novelty_type":"combinatorial_novelty","closest_prior":"FunSearch","framework_lineage":"evolution_of_heuristics","llm_model":"Qwen2.5-7B-Instruct-INT4","code_url":"https://github.com/whxru/CALM","new_benchmark":false,"confidence_results":"hi"},{"id":"2603.13344","title":"DyACE: Dynamic Algorithm Co-evolution for Online Automated Heuristic Design with Large Language Model","authors":["Guidong"],"affiliations":"","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-03-07","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper fundamentally challenges the static 'generate-once' paradigm of FunSearch and ReEvo by introducing dynamic, phase-specific heuristic co-evolution. The use of short-horizon rollouts to extract trajectory features directly aligns with our goal of improving search signals and sample efficiency in AlgoEvo.","relevance":{"methodological":8,"problem":9,"inspirational":9},"brief":"DyACE reformulates LLM-driven automated heuristic design from a static optimization task into a dynamic control problem, using a receding horizon architecture to continuously co-evolve phase-specific heuristic operators alongside the solution population. The results are backed by strong empirical numbers on JSSP, TSP, and CVRP, significantly outperforming state-of-the-art static baselines like ReEvo and FunSearch (e.g., reducing the optimality gap on CVRP CMT1 from ReEvo's 12.5% to 3.1%). The single most useful takeaway is the 'Look-Ahead Rollout Search' combined with a decoupled Diagnosis Agent: instead of evaluating an algorithm end-to-end, they run short rollouts to extract 'Search Trajectory Features' (landscape kinematics, operator telemetry) which an LLM translates into 'Verbal Gradients' to guide the next code mutation. This is a must-read for our AlgoEvo project; it directly addresses our bottlenecks in sample efficiency and search signaling by proving that dynamic, state-aware operator adaptation beats static heuristic generation, giving us a concrete architecture to steal.","specific_domain":"","methods":["evolutionary_algorithms","local_search","receding_horizon_control","llm_as_meta_controller","llm_code_generation","llm_evolutionary_search","llm_in_the_loop","llm_prompt_optimization"],"problems":["automated_heuristic_design","job_shop_scheduling","traveling_salesman_problem","capacitated_vehicle_routing_problem"],"problem_short":"AHD","benchmarks":["Taillard Benchmark (JSSP)","TSPLIB (TSP)","CVRPLIB (CMT dataset) (CVRP)"],"baselines":["GP","GEP","DRL Chen","DRL Zhang","DRL Liu","LSO","SPT/TWKR","FunSearch","EoH","ReEvo"],"vs_baselines":{"GP":"Avg +92.26% gap on JSSP vs DyACE","GEP":"Avg +80.18% gap on JSSP vs DyACE","DRL Chen":"Avg +115.00% gap on JSSP vs DyACE","DRL Zhang":"Avg +91.17% gap on JSSP vs DyACE","DRL Liu":"Avg +65.10% gap on JSSP vs DyACE","LSO":"Avg +219.14% gap on JSSP vs DyACE","SPT/TWKR":"Avg +127.09% gap on JSSP vs DyACE","FunSearch":"Avg +64.63% gap on JSSP; +3323.0% on TSP kroB200; +706.2% on CVRP CMT1 vs DyACE","EoH":"Avg +37.20% gap on JSSP; +212.1% on TSP kroB200; +437.5% on CVRP CMT1 vs DyACE","ReEvo":"Avg +31.57% gap on JSSP; +153.9% on TSP kroB200; +296.4% on CVRP CMT1 vs DyACE"},"novelty_type":"paradigm_shift","closest_prior":"ReEvo","framework_lineage":"reevo","llm_model":"GPT-4o-mini","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2602.15983","title":"ReLoop: Structured Modeling and Behavioral Verification for Reliable LLM-Based Optimization","authors":["Junbo"],"affiliations":"National University of Singapore, Northwestern University, City University of Hong Kong, Wenzhou University, Wenzhou Buyi Pharmacy Chain Co., Ltd.","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2026-02-17","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"The paper introduces 'behavioral verification'—using solver sensitivity to parameter perturbations as a proxy for semantic correctness without ground truth. This directly addresses the 'silent failure' problem in our OR-Bench and AlgoEvo pipelines, offering a concrete method to validate generated models/heuristics when ground truth is unavailable.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"ReLoop proposes a verification pipeline for LLM-generated optimization models that detects 'silent failures' (code that runs but solves the wrong problem) by perturbing input parameters and checking for expected solver objective shifts. They demonstrate that standard execution feasibility is a poor proxy for correctness (90% gap) on their new RetailOpt-190 benchmark, and that this perturbation testing significantly improves reliability. The critical takeaway is the use of sensitivity analysis as a ground-truth-free process reward signal: we can validate evolved algorithms in AlgoEvo by asserting that specific input perturbations *must* trigger output changes, filtering out semantically invalid candidates before expensive evaluation.","specific_domain":"multi_period_retail_inventory_optimization","methods":["chain_of_thought","behavioral_verification","solver_based_perturbation","iis_diagnostics","diagnosis_guided_repair","llm_code_generation","llm_in_the_loop","sensitivity_analysis"],"problems":["optimization_modeling","silent_failures","multi_period_retail_inventory_optimization","milp_general","program_synthesis"],"problem_short":"LLM-Opt Code Correctness","benchmarks":["RetailOpt-190","MAMO-ComplexLP","IndustryOR"],"baselines":["Claude Opus 4.6 Base","DeepSeek-V3.2 Base","Qwen3-32B Base","OptMATH-Qwen2.5-32B Base","SIRL-Qwen2.5-32B Base","CoT (Chain-of-Thought)"],"vs_baselines":{"Claude Opus 4.6 Base (RetailOpt-190)":"+27.9pp Exec%, +8.5pp Acc(10^-4)","DeepSeek-V3.2 Base (RetailOpt-190)":"+6.3pp Exec%, +5.3pp Acc(10^-4)","Claude Opus 4.6 Base (MAMO-ComplexLP)":"+9.4pp Acc(10^-6)","DeepSeek-V3.2 Base (IndustryOR)":"+12.0pp Acc(10^-6)"},"novelty_type":"combinatorial_novelty","closest_prior":"arXiv:2305.15030","framework_lineage":"reloop","llm_model":"","code_url":"https://github.com/junbolian/ReLoop","new_benchmark":true,"confidence_results":"hi"},{"id":"2603.03310","title":"Entropic-Time Inference: Self-Organizing Large Language Model Decoding Beyond Attention","authors":["Andrew"],"affiliations":"UC Berkeley","category":"OR for Generative AI","subdomain":"llm_serving_opt","date":"2026-02-08","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper fundamentally challenges the static 'token-per-step' assumption in our LLM serving optimization work (GPUSched) and offers a rigorous 'uncertainty-as-resource-allocator' heuristic that is directly transferable to improving sample efficiency in AlgoEvo.","relevance":{"methodological":8,"problem":8,"inspirational":9},"brief":"Kiruluta proposes 'Entropic-Time Inference,' a control framework that dynamically allocates compute (scheduling, attention, sampling) based on entropy reduction rather than token count, effectively skipping 'low-information' computation. While the 30-45% throughput gains over vLLM are self-reported and depend on efficient entropy estimation, the core mechanism is sound. The critical takeaway is the **'Entropic Time' metric**: we can steal this for AlgoEvo to allocate evolutionary compute only to solution branches with high uncertainty, rather than evolving all individuals uniformly. This directly addresses our sample efficiency bottleneck and provides a novel dynamic objective for our GPUSched project.","specific_domain":"llm_inference_optimization","methods":["entropy_control","self_organizing_systems","llm_inference_scheduling","attention_sparsification","adaptive_sampling","vllm","control_theory","feedback_control"],"problems":["llm_inference_optimization","throughput_optimization","latency_reduction","resource_allocation","kv_cache_management"],"problem_short":"LLM Inference Optimization","benchmarks":[],"baselines":["Standard Inference (fixed scheduling, dense attention, fixed-temperature sampling)","vLLM"],"vs_baselines":{"Standard Inference":"30-35% latency reduction, 30-45% throughput increase, 40-60% entropy reduction per compute increase, stable quality"},"novelty_type":"paradigm_shift","closest_prior":"vLLM","framework_lineage":"vllm","llm_model":"","code_url":null,"new_benchmark":false,"confidence_results":"hi"},{"id":"2601.21511","title":"LLaMEA-SAGE: Guiding Automated Algorithm Design with Structural Feedback from Explainable AI","authors":["Niki"],"affiliations":"Leiden University","category":"LLMs for Algorithm Design","subdomain":"evo_llm_search","date":"2026-01-29","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a concrete, implementable mechanism (AST features -> Surrogate -> SHAP -> Prompt) to provide structural feedback to the LLM, directly addressing our focus on 'better signal for search' and sample efficiency in AlgoEvo. It moves beyond simple fitness feedback to guiding the 'shape' of the code.","relevance":{"methodological":8,"problem":9,"inspirational":9},"brief":"LLaMEA-SAGE augments LLM-based evolutionary search by extracting AST features (complexity, graph metrics) from generated code, training a surrogate model to predict fitness from these features, and using SHAP analysis to generate natural language prompts that guide the LLM to modify specific structural properties (e.g., 'increase cyclomatic complexity'). On the MA-BBOB benchmark, it outperforms state-of-the-art methods (MCTS-AHD, LHNS) and converges faster than vanilla LLaMEA, although the authors honestly report that statistical significance was limited (p=0.44) due to small sample sizes (5 runs). The critical takeaway for us is the pipeline of using static code analysis as a feedback signal—we can immediately steal this 'SAGE' loop to guide AlgoEvo or EvoCut by telling the LLM *how* to structurally mutate code based on surrogate correlations, rather than just hoping for random improvements.","specific_domain":"black_box_optimization","methods":["llm_evolutionary_search","llm_code_generation","shap_analysis","explainable_ai","abstract_syntax_tree_analysis","static_code_analysis","xgboost","surrogate_modeling"],"problems":["black_box_optimization","continuous_optimization","heuristic_evolution"],"problem_short":"AAD","benchmarks":["SBOX-COST benchmark suite","Many Affine BBOB (MA-BBOB) benchmark"],"baselines":["Vanilla LLaMEA","MCTS-AHD [23]","LHNS [22]","NeighborhoodAdaptiveDE [16] (for validation only)"],"vs_baselines":{"LLaMEA (SBOX-COST)":"LLaMEA-SAGE achieves similar performance faster, with an average improvement of 11.1 AUC units and a large effect size (Cliff’s δ=0.60).","LLaMEA (MA-BBOB)":"LLaMEA-SAGE achieves better performance faster, with a medium effect size (Cliff’s δ=0.36), reaching fitness values LLaMEA cannot achieve within the full budget.","MCTS-AHD (MA-BBOB)":"LLaMEA-SAGE and vanilla LLaMEA clearly outperform MCTS-AHD.","LHNS (MA-BBOB)":"LLaMEA-SAGE and vanilla LLaMEA clearly outperform LHNS.","NeighborhoodAdaptiveDE (MA-BBOB validation)":"The best LLaMEA-SAGE algorithm beats NeighborhoodAdaptiveDE on 10d and 20d, but not on 5d (where NeighborhoodAdaptiveDE was specifically tuned)."},"novelty_type":"combinatorial_novelty","closest_prior":"LLaMEA","framework_lineage":"llamea","llm_model":"GPT-5-mini","code_url":"https://anonymous.4open.science/r/LLaMEA-SAGE/README.md","new_benchmark":false,"confidence_results":"hi"},{"id":"2511.09092","title":"OR-R1: Automating Modeling and Solving of Operations Research Optimization Problem via Test-Time Reinforcement Learning","authors":["Zezhen"],"affiliations":"The Hong Kong University of Science and Technology, Arizona State University, University of North Carolina at Chapel Hill","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-11-12","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper successfully applies Group Relative Policy Optimization (GRPO)—a critic-free RL method—to OR code generation, achieving state-of-the-art results with minimal data (100 samples). It provides a concrete blueprint for implementing 'RL-infused evolution' without the overhead of a value network, which is directly applicable to our AlgoEvo and MASPRM projects.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"OR-R1 introduces a data-efficient framework that fine-tunes Qwen3-8B using Supervised Fine-Tuning (SFT) followed by Test-Time Group Relative Policy Optimization (TGRPO) on unlabeled data. The results are empirically strong: it outperforms ORLM and LLMOPT while using only 1/10th of the synthetic training data, specifically narrowing the consistency gap between Pass@1 and Pass@8. The key takeaway for us is the effectiveness of GRPO (normalizing rewards within a sampled group to estimate baselines) combined with majority-voting rewards; this eliminates the need for a separate critic model while significantly improving code generation consistency. We should immediately evaluate GRPO as a lightweight alternative to PPO for the 'RL-infused' components of our evolutionary search methods.","specific_domain":"operations_research_problem_solving","methods":["supervised_fine_tuning","reinforcement_learning","proximal_policy_optimization","test_time_adaptation","llm_code_generation","llm_as_evaluator","llm_fine_tuned","llm_in_the_loop"],"problems":["operations_research_problem_solving","optimization_modeling","linear_programming","mixed_integer_linear_programming","resource_allocation","scheduling"],"problem_short":"OR Problem Modeling and Solving","benchmarks":["NL4Opt","MAMO Easy LP","MAMO Complex LP","NLP4LP","ComplexOR","IndustryOR","OptiBench","ICML Competition"],"baselines":["Qwen3-8B SFT(3K)","Qwen2.5-7B SFT(3K)","Llama3-8B SFT(3K)","Qwen3-8B SFT(100)","LLMOPT(Qwen2.5-14B)","ORLM(Llama3-8B)"],"vs_baselines":{"ORLM(Llama3-8B)":"+4.2% average accuracy","LLMOPT(Qwen2.5-14B)":"+7.6% average accuracy","Qwen3-8B SFT(3K)":"+3.1% average accuracy","Qwen3-8B SFT(100)":"+6.4% average accuracy"},"novelty_type":"combinatorial_novelty","closest_prior":"ORLM (Huang et al. 2025)","framework_lineage":"","llm_model":"Qwen3-8B","code_url":"https://github.com/SCUTE-ZZ/OR-R1","new_benchmark":false,"confidence_results":"lo"},{"id":"2510.27610","title":"ORGEval: Graph-Theoretic Evaluation of LLMs in Optimization Modeling","authors":["Zhuohan"],"affiliations":"The Chinese University of Hong Kong, Shenzhen, Shenzhen Research Institute of Big Data, Shenzhen International Center for Industrial and Applied Mathematics, Shenzhen Loop Area Institute","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-10-31","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a structural evaluation method (graph isomorphism) that replaces expensive solver execution for checking model correctness. This directly addresses the evaluation bottleneck in our 'OR benchmarking' and 'LLM reasoning evaluation' work, offering a way to validate generated models in seconds rather than hours.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Wang et al. propose ORGEval, a framework that evaluates LLM-generated optimization models by converting them into bipartite graphs and using the Weisfeiler-Lehman (WL) test to detect isomorphism with a ground truth, rather than solving the instances. They prove that for 'symmetric decomposable' graphs, this method is guaranteed to detect equivalence correctly, achieving 100% consistency and running in seconds compared to hours for solver-based checks on hard MIPLIB instances. The critical takeaway is the shift from execution-based to **structural evaluation**: we can validate model logic via graph topology ($O(k(m+n)^2)$) without incurring the cost of solving NP-hard problems. This is immediately actionable for our OR benchmarking pipelines and could serve as a rapid 'pre-solve' filter in our evolutionary search loops to reject structurally invalid candidates instantly.","specific_domain":"llm_optimization_modeling_evaluation","methods":["graph_theory","weisfeiler_lehman_test","graph_isomorphism","bipartite_graphs","hashing","symmetric_decomposable_graphs"],"problems":["llm_evaluation","milp_modeling","lp_modeling","model_equivalence_detection"],"problem_short":"MILP/LP Model Equivalence","benchmarks":["Bench4Opt","MIPLIB"],"baselines":["Solver-based evaluation (optimal value comparison)","Canonical accuracy"],"vs_baselines":{"Solver-based evaluation":"100% consistency vs 94.11% average consistency on LLM-generated models; runtime 0.21s-32.07s vs >1 hour for hard/open problems."},"novelty_type":"combinatorial_novelty","closest_prior":"On representing linear programs by graph neural networks (Chen et al., 2022b)","framework_lineage":"wl_test_for_milp_graphs","llm_model":"","code_url":null,"new_benchmark":true,"confidence_results":"hi"},{"id":"2510.18428","title":"AlphaOPT: Formulating Optimization Programs with Self-Improving LLM Experience Library","authors":["Minwei"],"affiliations":"Massachusetts Institute of Technology, London School of Economics and Political Science, University of Florida, Northeastern University, Singapore Management University, Singapore-MIT Alliance for Research and Technology","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-10-21","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper sits exactly at the intersection of our two primary interests: OR formulation (OR-Bench) and evolutionary memory systems (AlgoEvo). The 'Library Evolution' mechanism—specifically refining retrieval conditions based on solver feedback—offers a concrete solution to the 'memory pollution' and 'misapplication' problems we face in long-running evolutionary search.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"AlphaOPT introduces a 'Library Evolution' mechanism that iteratively refines the *applicability conditions* of cached optimization insights based on solver feedback, allowing it to learn from answers alone (no gold programs). On OOD benchmarks like OptiBench, it beats fine-tuned models (ORLM) by ~13% and shows consistent scaling with data size. **Key Takeaway:** The specific mechanism of diagnosing 'unretrieved' vs. 'negative' tasks to rewrite retrieval triggers is a transferable technique for our AlgoEvo memory; it solves the problem of heuristic misapplication in long-term search. We should implement this 'condition refinement' loop immediately to improve our multi-agent memory systems.","specific_domain":"optimization_program_formulation","methods":["llm_as_heuristic","llm_code_generation","llm_in_the_loop","llm_evolutionary_search","llm_as_evaluator","retrieval_augmented_generation","program_synthesis","evolution_of_heuristics"],"problems":["optimization_program_formulation","milp_general","nlp_general","combinatorial_optimization","heuristic_evolution"],"problem_short":"OPF","benchmarks":["NLP4LP","NL4OPT","IndustryOR","MAMO (ComplexLP)","LogiOR","Optibench"],"baselines":["Standard","Reflexion","OptiMUS","ORThought","ORLM","LLMOPT"],"vs_baselines":{"ORThought":"AlphaOPT (self-exploration) +7.7% on OptiBench","ORLM":"AlphaOPT (full) +13.6% on OptiBench","LLMOPT":"AlphaOPT (full) +25.4% on OptiBench, but -13.7% on NLP4LP (in-distribution)"},"novelty_type":"combinatorial_novelty","closest_prior":"ExpeL (Zhao et al., 2024)","framework_lineage":"","llm_model":"GPT-4o","code_url":"https://github.com/Minw913/AlphaOPT","new_benchmark":false,"confidence_results":"hi"},{"id":"2510.04204","title":"CALM Before the STORM: Unlocking Native Reasoning for Optimization Modeling","authors":["Zhengyang"],"affiliations":"Qwen Team, Alibaba Inc., The Chinese University of Hong Kong, Shenzhen, Southern University of Science and Technology, Shanghai University of Finance and Economics, Shenzhen Loop Area Institute (SLAI)","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2025-10-05","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper directly addresses the 'Code Utilization Distrust' failure mode—where models simulate logic in text rather than using tools—which is a primary bottleneck in our AlgoEvo and OR-Bench work. It provides a proven, automated 'Intervener' workflow to fix this via RL, achieving SOTA with a 4B model, offering a concrete blueprint to improve our agent reliability.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Tang et al. propose CALM, a framework that uses an expert 'Intervener' model to inject corrective hints into a small LRM's reasoning trace (e.g., forcing it to use Python instead of manual calculation), followed by SFT and RL (GRPO). Results are strong and verified: a 4B model matches DeepSeek-R1 (671B) on OR benchmarks, specifically fixing the 'Code Utilization Distrust' we see in our own agents. The key takeaway is the 'Intervener' loop: instead of discarding failed traces, they repair them with hints to create a 'golden' reasoning dataset that preserves the 'thinking' process while enforcing tool use. This is a direct, actionable method for improving our AlgoEvo agents' reliability in generating executable heuristics without massive human annotation.","specific_domain":"automated_optimization_modeling","methods":["llm_as_heuristic","llm_as_evaluator","llm_code_generation","llm_in_the_loop","llm_fine_tuned","reinforcement_learning","supervised_learning","program_synthesis"],"problems":["automated_optimization_modeling","mathematical_modeling","milp_general","lp_formulation"],"problem_short":"OM","benchmarks":["NL4Opt","MAMO-Easy","MAMO-Complex","IndustryOR","OptMath"],"baselines":["GPT-3.5-Turbo","GPT-4","DeepSeek-V3","DeepSeek-R1-0528","Qwen3-235B-A22B-Thinking-2507","Chain-of-Experts","OptiMUS","LLMOPT-Qwen2.5-14B","ORLM-LLaMA-3-8B","OptMATH-Qwen2.5-7B","SIRL-Qwen2.5-7B","Qwen3-4B-Thinking-2507 (Base)"],"vs_baselines":{"GPT-3.5-Turbo":"+23.6% Macro AVG (68.9% vs 45.3%)","GPT-4":"+13.9% Macro AVG (68.9% vs 55.0%)","DeepSeek-V3":"+7.9% Macro AVG (68.9% vs 61.0%)","DeepSeek-R1-0528":"+1.4% Macro AVG (68.9% vs 67.5%)","Qwen3-235B-A22B-Thinking-2507":"+5.0% Macro AVG (68.9% vs 63.9%)","OptiMUS":"+19.5% Macro AVG (68.9% vs 49.4%)","LLMOPT-Qwen2.5-14B":"+17.8% Macro AVG (68.9% vs 51.1%)","ORLM-LLaMA-3-8B":"+19.7% Macro AVG (68.9% vs 49.2%)","OptMATH-Qwen2.5-7B":"+13.5% Macro AVG (68.9% vs 55.4%)","SIRL-Qwen2.5-7B":"+6.8% Macro AVG (68.9% vs 62.1%)","Qwen3-4B-Thinking-2507 (Base)":"+11.8% Macro AVG (68.9% vs 57.1%) and +23.8% on MAMO-Complex (70.3% vs 46.5%)"},"novelty_type":"paradigm_shift","closest_prior":"SIRL (Chen et al., 2025)","framework_lineage":"calm","llm_model":"Qwen3-4B-Thinking-2507","code_url":"https://github.com/tangzhy/STORM","new_benchmark":false,"confidence_results":"lo"},{"id":"2411.01679","title":"Autoformulation of Mathematical Optimization Models Using LLMs","authors":["Nicolás"],"affiliations":"University of Cambridge, University of Hawaii at Manoa","category":"Generative AI for OR","subdomain":"nl_to_opt","date":"2024-11-03","priority":8.26,"must_read":true,"changes_thinking":true,"team_discussion":true,"reasoning":"This paper introduces a rigorous mechanism (SMT-based symbolic pruning) to handle redundancy in LLM-generated mathematical structures, which is directly transferable to our evolutionary search pipelines (AlgoEvo/EvoCut) to drastically improve sample efficiency. It also establishes a new baseline for our OR benchmarking work.","relevance":{"methodological":8,"problem":9,"inspirational":8},"brief":"Astorga et al. frame optimization modeling as a hierarchical Monte-Carlo Tree Search (MCTS) problem, using LLMs to generate components and—crucially—employing SMT solvers to prune mathematically equivalent branches (e.g., recognizing `x+y` and `y+x` as identical). They achieve SOTA results on NL4OPT and IndustryOR, outperforming fine-tuned models like ORLM while using significantly fewer samples than naive approaches. **Key Takeaway:** The integration of symbolic equivalence checking (SMT) to prune the search tree is a technique we should immediately steal; implementing this in AlgoEvo would allow us to discard functionally identical code/math mutants before expensive evaluation, directly addressing our sample efficiency bottleneck.","specific_domain":"automated_optimization_modeling","methods":["monte_carlo_tree_search","llm_in_the_loop","llm_as_heuristic","llm_as_evaluator","symbolic_pruning","smt_solvers","hierarchical_decomposition","dual_reward_system"],"problems":["automated_optimization_modeling","program_synthesis","linear_programming","mixed_integer_programming","convex_optimization","non_convex_optimization"],"problem_short":"Autoformulation","benchmarks":["NL4OPT","IndustryOR","MAMO (ComplexLP)","ComplexOR"],"baselines":["ORLMLlama3-8B","Standard (zero-shot prompting)","Reflexion","Chain-of-Experts","OptiMUS","Tree-of-Thought (DFS)","Sequential (naive sampling)"],"vs_baselines":{"ORLMLlama3-8B":"Autoformulator (All) outperforms by +6.92% on NL4OPT, +10.0% on IndustryOR, +23.0% on MAMO (ComplexLP), +27.8% on ComplexOR.","OptiMUS":"Autoformulator (All) outperforms by +13.82% on NL4OPT and +5.5% on ComplexOR.","Chain-of-Experts":"Autoformulator (All) outperforms by +22.1% on MAMO (ComplexLP).","Tree-of-Thought (N=3)":"Autoformulator (N=3) significantly outperforms across all benchmarks (e.g., +25.68% on NL4OPT).","Sequential (N=3)":"Autoformulator (N=3) significantly outperforms across all benchmarks (e.g., +31.39% on NL4OPT)."},"novelty_type":"combinatorial_novelty","closest_prior":"arXiv:2309.08532","framework_lineage":"","llm_model":"GPT4-0613","code_url":"https://github.com/jumpynitro/AutoFormulator","new_benchmark":false,"confidence_results":"lo"}];
